import type { NotebookCell } from '@/lib/types/notebook-cell';

const CELLS_STREAMING_01_SQL_SERVER_CDC: NotebookCell[] = [
  {
    "id": "streaming-01-sql-server-cdc-c0",
    "type": "markdown",
    "source": "# Streaming: SQL Server CDC via Debezium/SHIR\n\nCaptures row-level change events from on-premises SQL Server using the\nSelf-hosted Integration Runtime (SHIR) and Debezium CDC connector, ingested\nthrough Microsoft Fabric Eventstreams into the Bronze Delta Lake table.\n\n**Architecture:** SQL Server → SHIR → Eventstream (Debezium) → Bronze Delta\n\n| Setting | Value |\n|---|---|\n| Source | On-prem SQL Server 2019+ |\n| CDC Method | SQL Server native CDC + Debezium |\n| Sink | `lh_bronze.bronze_cdc_sql_server` |\n| Trigger | Continuous micro-batch (2s) |"
  },
  {
    "id": "streaming-01-sql-server-cdc-c1",
    "type": "markdown",
    "source": "## 1. Configuration — SHIR Connection & CDC Tables"
  },
  {
    "id": "streaming-01-sql-server-cdc-c2",
    "type": "code",
    "source": "import os\n\nfrom pyspark.sql import SparkSession\nfrom pyspark.sql import functions as F\nfrom pyspark.sql.types import (\n    BooleanType,\n    DecimalType,\n    IntegerType,\n    LongType,\n    MapType,\n    StringType,\n    StructField,\n    StructType,\n    TimestampType,\n)\n\nspark = SparkSession.builder.getOrCreate()\n\n# ---------------------------------------------------------------------------\n# Connection configuration — all secrets sourced from environment / Key Vault\n# NOTE: In Fabric, use the built-in Secret Manager or reference a linked\n#       Azure Key Vault via mssparkutils.credentials.getSecret()\n# ---------------------------------------------------------------------------\ntry:\n    from notebookutils import mssparkutils\n    EVENTSTREAM_CONN_STR = mssparkutils.credentials.getSecret(\n        \"kv-casino-poc\", \"eventstream-cdc-connection-string\"\n    )\n    CHECKPOINT_STORAGE = mssparkutils.credentials.getSecret(\n        \"kv-casino-poc\", \"adls-checkpoint-path\"\n    )\nexcept ImportError:\n    # Local / unit-test fallback — never use real credentials here\n    EVENTSTREAM_CONN_STR = os.getenv(\"EVENTSTREAM_CONN_STR\", \"\")\n    CHECKPOINT_STORAGE = os.getenv(\"CHECKPOINT_PATH\", os.environ.get('CHECKPOINT_PATH_BASE', 'abfss://Files/checkpoints') + '')\n\n# Eventstream / Kafka endpoint exposed by Fabric Eventstreams\nKAFKA_BOOTSTRAP_SERVERS = os.getenv(\n    \"EVENTSTREAM_KAFKA_ENDPOINT\",\n    \"<your-eventstream>.servicebus.windows.net:9093\"\n)\nKAFKA_TOPIC_TRANSACTIONS = \"casino.dbo.Transactions\"\nKAFKA_TOPIC_PLAYERS     = \"casino.dbo.Players\"\n\n# Delta Lake target paths (Fabric Lakehouse)\nBRONZE_TABLE   = \"lh_bronze.bronze_cdc_sql_server\"\nCHECKPOINT_DIR = f\"{CHECKPOINT_STORAGE}/cdc_sql_server\"\n\n# NOTE: Fabric Lakehouse tables are accessed via the three-part name\n#       workspace.lakehouse.table when using cross-workspace references.",
    "lang": "pyspark"
  },
  {
    "id": "streaming-01-sql-server-cdc-c3",
    "type": "markdown",
    "source": "## 2. Enable CDC on SQL Server — Run Once Against Source DB\n\nExecute the following SQL directly on the SQL Server instance via SSMS\nor a linked service query. **Not executed by this notebook.**"
  },
  {
    "id": "streaming-01-sql-server-cdc-c4",
    "type": "code",
    "source": "CDC_ENABLE_SQL = \"\"\"\n-- Step 1: Enable CDC at database level (requires sysadmin or db_owner)\nUSE casino;\nGO\nEXEC sys.sp_cdc_enable_db;\nGO\n\n-- Step 2: Enable CDC on Transactions table\nEXEC sys.sp_cdc_enable_table\n    @source_schema = N'dbo',\n    @source_name   = N'Transactions',\n    @role_name     = NULL,          -- NULL = no gating role restriction\n    @capture_instance = N'dbo_Transactions',\n    @supports_net_changes = 1;\nGO\n\n-- Step 3: Enable CDC on Players table\nEXEC sys.sp_cdc_enable_table\n    @source_schema = N'dbo',\n    @source_name   = N'Players',\n    @role_name     = NULL,\n    @capture_instance = N'dbo_Players',\n    @supports_net_changes = 1;\nGO\n\n-- Verify CDC is enabled\nSELECT name, is_cdc_enabled FROM sys.databases WHERE name = 'casino';\nSELECT capture_instance, source_schema, source_table, start_lsn\nFROM cdc.change_tables;\n\"\"\"\n\nprint(\"CDC enablement SQL (run on source SQL Server):\")\nprint(CDC_ENABLE_SQL)",
    "lang": "pyspark"
  },
  {
    "id": "streaming-01-sql-server-cdc-c5",
    "type": "markdown",
    "source": "## 3. Debezium CDC Envelope Schema\n\nDebezium serialises each change as a JSON envelope containing operation\ntype, the before/after row images, LSN (Log Sequence Number), and source\nmetadata. The schema below matches Debezium SQL Server connector v2.x."
  },
  {
    "id": "streaming-01-sql-server-cdc-c6",
    "type": "code",
    "source": "# Inner schema shared by before/after row images for Transactions\ntransaction_row_schema = StructType([\n    StructField(\"TransactionId\",   StringType(),  nullable=True),\n    StructField(\"PlayerId\",        StringType(),  nullable=True),\n    StructField(\"MachineId\",       StringType(),  nullable=True),\n    StructField(\"Amount\",          DecimalType(18, 2), nullable=True),\n    StructField(\"TransactionType\", StringType(),  nullable=True),  # BET, WIN, DEPOSIT\n    StructField(\"GameCode\",        StringType(),  nullable=True),\n    StructField(\"CreatedAt\",       TimestampType(), nullable=True),\n    StructField(\"IsVoided\",        BooleanType(), nullable=True),\n])\n\n# Inner schema for Players row images\nplayer_row_schema = StructType([\n    StructField(\"PlayerId\",      StringType(), nullable=True),\n    StructField(\"LoyaltyTier\",   StringType(), nullable=True),\n    StructField(\"FirstVisit\",    TimestampType(), nullable=True),\n    StructField(\"TotalWagered\",  DecimalType(18, 2), nullable=True),\n    StructField(\"IsExcluded\",    BooleanType(), nullable=True),\n])\n\n# Full Debezium envelope schema (source metadata + before/after images)\ndebezium_envelope_schema = StructType([\n    StructField(\"op\",        StringType(), nullable=False),   # c=create, u=update, d=delete, r=read(snapshot)\n    StructField(\"ts_ms\",     LongType(),   nullable=False),   # event timestamp (epoch ms)\n    StructField(\"lsn\",       StringType(), nullable=True),    # SQL Server LSN hex string\n    StructField(\"source\", StructType([\n        StructField(\"version\",  StringType(), nullable=True),\n        StructField(\"connector\", StringType(), nullable=True),\n        StructField(\"db\",       StringType(), nullable=True),\n        StructField(\"schema\",   StringType(), nullable=True),\n        StructField(\"table\",    StringType(), nullable=True),\n        StructField(\"commit_lsn\", StringType(), nullable=True),\n        StructField(\"change_lsn\", StringType(), nullable=True),\n    ]), nullable=True),\n    StructField(\"before\",    transaction_row_schema, nullable=True),  # NULL for inserts\n    StructField(\"after\",     transaction_row_schema, nullable=True),  # NULL for deletes\n])",
    "lang": "pyspark"
  },
  {
    "id": "streaming-01-sql-server-cdc-c7",
    "type": "markdown",
    "source": "## 4. Read CDC Stream from Eventstreams (Kafka Protocol)\n\nFabric Eventstreams exposes a Kafka-compatible endpoint. The SASL/SSL\nsettings below are required for the managed endpoint.\n\nNOTE: Set `startingOffsets` to `\"earliest\"` for initial backfill,\n      then switch to `\"latest\"` for steady-state streaming."
  },
  {
    "id": "streaming-01-sql-server-cdc-c8",
    "type": "code",
    "source": "raw_cdc_stream = (\n    spark.readStream\n    .format(\"kafka\")\n    .option(\"kafka.bootstrap.servers\", KAFKA_BOOTSTRAP_SERVERS)\n    .option(\"kafka.security.protocol\", \"SASL_SSL\")\n    .option(\"kafka.sasl.mechanism\", \"PLAIN\")\n    .option(\n        \"kafka.sasl.jaas.config\",\n        f'org.apache.kafka.common.security.plain.PlainLoginModule required '\n        f'username=\"$ConnectionString\" '\n        f'password=\"{EVENTSTREAM_CONN_STR}\";'\n    )\n    .option(\"subscribe\", f\"{KAFKA_TOPIC_TRANSACTIONS},{KAFKA_TOPIC_PLAYERS}\")\n    .option(\"startingOffsets\", \"latest\")\n    .option(\"maxOffsetsPerTrigger\", 50_000)   # back-pressure control\n    .option(\"failOnDataLoss\", \"false\")         # tolerate Eventstream retention gaps\n    .load()\n)\n\nprint(\"CDC stream schema:\")\nraw_cdc_stream.printSchema()",
    "lang": "pyspark"
  },
  {
    "id": "streaming-01-sql-server-cdc-c9",
    "type": "markdown",
    "source": "## 5. Parse CDC Envelope — Before/After Images\n\nExtracts the Debezium envelope, normalises operation codes, and adds\nFabric-standard audit columns."
  },
  {
    "id": "streaming-01-sql-server-cdc-c10",
    "type": "code",
    "source": "parsed_cdc = (\n    raw_cdc_stream\n    # Kafka value is bytes → cast to string then parse JSON\n    .withColumn(\"value_str\", F.col(\"value\").cast(\"string\"))\n    .withColumn(\"key_str\",   F.col(\"key\").cast(\"string\"))\n    .withColumn(\"envelope\",  F.from_json(F.col(\"value_str\"), debezium_envelope_schema))\n    # Flatten envelope fields\n    .select(\n        F.col(\"topic\").alias(\"cdc_topic\"),\n        F.col(\"partition\").alias(\"kafka_partition\"),\n        F.col(\"offset\").alias(\"kafka_offset\"),\n        F.col(\"envelope.op\").alias(\"cdc_operation\"),\n        F.col(\"envelope.lsn\").alias(\"sql_lsn\"),\n        F.col(\"envelope.ts_ms\").alias(\"event_epoch_ms\"),\n        F.to_timestamp(\n            F.from_unixtime(F.col(\"envelope.ts_ms\") / 1000)\n        ).alias(\"event_timestamp\"),\n        F.col(\"envelope.source.table\").alias(\"source_table\"),\n        F.col(\"envelope.before\").alias(\"before_image\"),\n        F.col(\"envelope.after\").alias(\"after_image\"),\n        # Resolve the effective row: after for inserts/updates, before for deletes\n        F.when(F.col(\"envelope.op\").isin(\"c\", \"u\", \"r\"), F.col(\"envelope.after\"))\n         .when(F.col(\"envelope.op\") == \"d\",              F.col(\"envelope.before\"))\n         .alias(\"effective_row\"),\n    )\n    # Map Debezium op codes to readable labels\n    .withColumn(\"operation_label\",\n        F.when(F.col(\"cdc_operation\") == \"c\", F.lit(\"INSERT\"))\n         .when(F.col(\"cdc_operation\") == \"u\", F.lit(\"UPDATE\"))\n         .when(F.col(\"cdc_operation\") == \"d\", F.lit(\"DELETE\"))\n         .when(F.col(\"cdc_operation\") == \"r\", F.lit(\"SNAPSHOT\"))\n         .otherwise(F.lit(\"UNKNOWN\"))\n    )\n    # Fabric audit columns\n    .withColumn(\"ingested_at\", F.current_timestamp())\n    .withColumn(\"ingestion_source\", F.lit(\"sql_server_cdc_debezium\"))\n)",
    "lang": "pyspark"
  },
  {
    "id": "streaming-01-sql-server-cdc-c11",
    "type": "markdown",
    "source": "## 6. Handle Schema Evolution\n\nWhen the source schema changes, Debezium can emit schema-change events.\nThe Bronze layer stores the raw JSON so downstream Silver jobs can replay\nwith updated parsing logic without data loss.\n\nNOTE: Fabric Delta Lake supports `mergeSchema` and `overwriteSchema`.\n      For CDC Bronze, always use `mergeSchema=true` to accommodate additive\n      column additions without pipeline interruption."
  },
  {
    "id": "streaming-01-sql-server-cdc-c12",
    "type": "code",
    "source": "# Preserve the raw JSON payload alongside parsed fields for schema-evolution safety\ncdc_with_raw = parsed_cdc.withColumn(\"raw_payload\", F.col(\"value_str\") if \"value_str\" in [c.name for c in parsed_cdc.schema] else F.lit(None).cast(StringType()))\n\n# NOTE: If the source schema adds columns, mergeSchema will add them to Delta\n#       automatically. Dropped columns remain in Delta with NULL values.",
    "lang": "pyspark"
  },
  {
    "id": "streaming-01-sql-server-cdc-c13",
    "type": "markdown",
    "source": "## 7. Write to Delta Lake Bronze Table"
  },
  {
    "id": "streaming-01-sql-server-cdc-c14",
    "type": "code",
    "source": "def write_cdc_stream(df, epoch_id):\n    \"\"\"\n    Micro-batch writer — appends each batch to the Bronze Delta table.\n    Epoch ID is passed by Spark Structured Streaming for idempotency.\n    \"\"\"\n    if df.isEmpty():\n        return\n\n    (\n        df.write\n        .format(\"delta\")\n        .mode(\"append\")\n        .option(\"mergeSchema\", \"true\")\n        # NOTE: partitionBy is set at table creation; subsequent writes inherit it.\n        .partitionBy(\"source_table\", F.to_date(F.col(\"event_timestamp\")).cast(\"string\") if False else \"ingested_at\")\n        .saveAsTable(BRONZE_TABLE)\n    )\n    print(f\"[Epoch {epoch_id}] Wrote {spark.table(BRONZE_TABLE).count()} CDC records to {BRONZE_TABLE}\")\n\n\n# Append-mode streaming query with 2-second micro-batches\ncdc_query = (\n    parsed_cdc\n    .writeStream\n    .format(\"delta\")\n    .outputMode(\"append\")\n    .option(\"checkpointLocation\", CHECKPOINT_DIR)\n    .option(\"mergeSchema\", \"true\")\n    .partitionBy(\"source_table\")\n    .trigger(processingTime=\"2 seconds\")\n    .toTable(BRONZE_TABLE)\n)\n\nprint(f\"Streaming query started: {cdc_query.id}\")\nprint(f\"Status: {cdc_query.status}\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-01-sql-server-cdc-c15",
    "type": "markdown",
    "source": "## 8. Monitoring Queries"
  },
  {
    "id": "streaming-01-sql-server-cdc-c16",
    "type": "code",
    "source": "# NOTE: Run these in a separate cell / notebook while the stream is active.\n#       Fabric Real-Time Hub also provides built-in Eventstream monitoring.\n\nmonitoring_sql = f\"\"\"\n-- Event counts by operation type (last 1 hour)\nSELECT\n    source_table,\n    operation_label,\n    COUNT(*)                          AS event_count,\n    MIN(event_timestamp)              AS earliest_event,\n    MAX(event_timestamp)              AS latest_event,\n    CURRENT_TIMESTAMP - MAX(event_timestamp) AS approx_lag\nFROM {BRONZE_TABLE}\nWHERE ingested_at >= CURRENT_TIMESTAMP - INTERVAL 1 HOUR\nGROUP BY source_table, operation_label\nORDER BY source_table, operation_label;\n\n-- Latency percentiles (ingestion lag vs event timestamp)\nSELECT\n    source_table,\n    PERCENTILE_CONT(0.50) WITHIN GROUP (ORDER BY latency_seconds) AS p50_latency_s,\n    PERCENTILE_CONT(0.95) WITHIN GROUP (ORDER BY latency_seconds) AS p95_latency_s,\n    PERCENTILE_CONT(0.99) WITHIN GROUP (ORDER BY latency_seconds) AS p99_latency_s\nFROM (\n    SELECT\n        source_table,\n        UNIX_TIMESTAMP(ingested_at) - (event_epoch_ms / 1000) AS latency_seconds\n    FROM {BRONZE_TABLE}\n    WHERE ingested_at >= CURRENT_TIMESTAMP - INTERVAL 15 MINUTE\n) t\nGROUP BY source_table;\n\"\"\"\n\nprint(\"Monitoring SQL (execute against Lakehouse SQL endpoint):\")\nprint(monitoring_sql)\n\n# Stream status check (call while query is running)\nif \"cdc_query\" in dir() and cdc_query.isActive:\n    progress = cdc_query.lastProgress\n    if progress:\n        print(f\"Input rows/s  : {progress.get('inputRowsPerSecond', 'N/A')}\")\n        print(f\"Process rows/s: {progress.get('processedRowsPerSecond', 'N/A')}\")\n        print(f\"Batch duration: {progress.get('batchDuration', 'N/A')} ms\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-01-sql-server-cdc-c17",
    "type": "markdown",
    "source": "## 9. Cleanup — Stop Streaming Query"
  },
  {
    "id": "streaming-01-sql-server-cdc-c18",
    "type": "code",
    "source": "# Graceful shutdown — call this cell to stop the streaming query\ndef stop_cdc_stream(query_name: str = None):\n    \"\"\"Stop the CDC streaming query gracefully.\"\"\"\n    for q in spark.streams.active:\n        if query_name is None or q.name == query_name:\n            q.stop()\n            print(f\"Stopped streaming query: {q.id}\")\n\n# Uncomment to stop:\n# stop_cdc_stream()\n\n# List all active streaming queries\nactive = spark.streams.active\nprint(f\"Active streaming queries: {len(active)}\")\nfor q in active:\n    print(f\"  - {q.id} | name={q.name} | status={q.status['message']}\")",
    "lang": "pyspark"
  }
];

const CELLS_STREAMING_02_AZURE_SQL_CHANGE_FEED: NotebookCell[] = [
  {
    "id": "streaming-02-azure-sql-change-feed-c0",
    "type": "markdown",
    "source": "# Streaming: Azure SQL Database Change Feed\n\nProcesses change data from Azure SQL Database using SQL Server Change\nTracking (CT) and Fabric Mirroring. Changes are applied as upserts to the\nBronze Delta Lake table, preserving the full mutation history.\n\n**Architecture:** Azure SQL DB → Fabric Mirroring (GA) → Bronze Delta\n**Alternative:** Azure SQL DB → Change Tracking → JDBC Polling → Bronze Delta\n\n| Setting | Value |\n|---|---|\n| Source | Azure SQL Database (General Purpose / Business Critical) |\n| CT Method | SQL Server Change Tracking v2 |\n| Preferred GA Method | Fabric Database Mirroring |\n| Sink | `lh_bronze.bronze_cdc_azure_sql` |\n| Write Mode | MERGE (upsert) |"
  },
  {
    "id": "streaming-02-azure-sql-change-feed-c1",
    "type": "markdown",
    "source": "## 1. Configuration — Azure SQL Connection & Change Tracking"
  },
  {
    "id": "streaming-02-azure-sql-change-feed-c2",
    "type": "code",
    "source": "import os\n\nfrom delta.tables import DeltaTable\nfrom pyspark.sql import SparkSession\nfrom pyspark.sql import functions as F\nfrom pyspark.sql.types import (\n    BooleanType,\n    DecimalType,\n    IntegerType,\n    LongType,\n    StringType,\n    StructField,\n    StructType,\n    TimestampType,\n)\n\nspark = SparkSession.builder.getOrCreate()\n\n# ---------------------------------------------------------------------------\n# Connection configuration — all secrets sourced from Key Vault\n# NOTE: In Fabric, use mssparkutils.credentials.getSecret() to avoid\n#       embedding connection strings in notebook source.\n# ---------------------------------------------------------------------------\ntry:\n    from notebookutils import mssparkutils\n    AZURE_SQL_JDBC_URL = mssparkutils.credentials.getSecret(\n        \"kv-casino-poc\", \"azure-sql-jdbc-url\"\n    )\n    AZURE_SQL_USER     = mssparkutils.credentials.getSecret(\n        \"kv-casino-poc\", \"azure-sql-username\"\n    )\n    AZURE_SQL_PASSWORD = mssparkutils.credentials.getSecret(\n        \"kv-casino-poc\", \"azure-sql-password\"\n    )\n    CHECKPOINT_STORAGE = mssparkutils.credentials.getSecret(\n        \"kv-casino-poc\", \"adls-checkpoint-path\"\n    )\nexcept ImportError:\n    AZURE_SQL_JDBC_URL = os.getenv(\"AZURE_SQL_JDBC_URL\", \"\")\n    AZURE_SQL_USER     = os.getenv(\"AZURE_SQL_USER\", \"\")\n    AZURE_SQL_PASSWORD = os.getenv(\"AZURE_SQL_PASSWORD\", \"\")\n    CHECKPOINT_STORAGE = os.getenv(\"CHECKPOINT_PATH\", os.environ.get('CHECKPOINT_PATH_BASE', 'abfss://Files/checkpoints') + '')\n\n# JDBC properties dict (used for batch reads during CT polling)\njdbc_properties = {\n    \"user\":     AZURE_SQL_USER,\n    \"password\": AZURE_SQL_PASSWORD,\n    \"driver\":   \"com.microsoft.sqlserver.jdbc.SQLServerDriver\",\n    \"encrypt\":  \"true\",\n    \"trustServerCertificate\": \"false\",\n    \"hostNameInCertificate\":  \"*.database.windows.net\",\n    \"loginTimeout\": \"30\",\n}\n\n# Target tables in Azure SQL Database\nCT_TABLES = {\n    \"Orders\":           {\"schema\": \"dbo\", \"pk\": \"OrderId\"},\n    \"CustomerActivity\": {\"schema\": \"dbo\", \"pk\": \"ActivityId\"},\n}\n\n# Delta Lake target\nBRONZE_TABLE   = \"lh_bronze.bronze_cdc_azure_sql\"\nCHECKPOINT_DIR = f\"{CHECKPOINT_STORAGE}/cdc_azure_sql\"\nCT_VERSION_DIR = f\"{CHECKPOINT_STORAGE}/ct_versions\"  # persists last sync version\n\n# NOTE: Fabric Database Mirroring (GA) is the recommended approach for\n#       Azure SQL Database — it replicates the entire database without\n#       requiring JDBC polling. This notebook covers the JDBC/CT fallback.",
    "lang": "pyspark"
  },
  {
    "id": "streaming-02-azure-sql-change-feed-c3",
    "type": "markdown",
    "source": "## 2. Enable Change Tracking on Azure SQL — Run Once Against Source DB\n\nExecute in Azure SQL Database via SSMS, Azure Data Studio, or the\nQuery editor in the Azure portal. **Not executed by this notebook.**"
  },
  {
    "id": "streaming-02-azure-sql-change-feed-c4",
    "type": "code",
    "source": "CHANGE_TRACKING_SQL = \"\"\"\n-- Step 1: Enable Change Tracking at database level\n--   CHANGE_RETENTION: how long CT data is retained (DAYS)\n--   AUTO_CLEANUP: automatically purge expired CT entries\nALTER DATABASE casino\nSET CHANGE_TRACKING = ON\n(CHANGE_RETENTION = 2 DAYS, AUTO_CLEANUP = ON);\nGO\n\n-- Step 2: Enable Change Tracking on Orders table\nALTER TABLE dbo.Orders\nENABLE CHANGE_TRACKING\nWITH (TRACK_COLUMNS_UPDATED = ON);  -- record which columns changed\nGO\n\n-- Step 3: Enable Change Tracking on CustomerActivity table\nALTER TABLE dbo.CustomerActivity\nENABLE CHANGE_TRACKING\nWITH (TRACK_COLUMNS_UPDATED = ON);\nGO\n\n-- Verify CT is enabled\nSELECT\n    DB_NAME()                       AS database_name,\n    is_auto_cleanup_on,\n    retention_period,\n    retention_period_units_desc\nFROM sys.change_tracking_databases;\n\n-- Get the current minimum valid CT version (must use this as baseline)\nSELECT CHANGE_TRACKING_MIN_VALID_VERSION(OBJECT_ID('dbo.Orders')) AS min_valid_version;\nSELECT CHANGE_TRACKING_CURRENT_VERSION()                          AS current_version;\n\"\"\"\n\nprint(\"Change Tracking SQL (run on Azure SQL Database):\")\nprint(CHANGE_TRACKING_SQL)",
    "lang": "pyspark"
  },
  {
    "id": "streaming-02-azure-sql-change-feed-c5",
    "type": "code",
    "source": "# MAGIC %md\n# MAGIC ## 3. Fabric Mirroring Setup (Preferred GA Method)\n# MAGIC\n# MAGIC Microsoft Fabric Database Mirroring replicates Azure SQL Database\n# MAGIC continuously without custom JDBC polling. Configure via the Fabric portal:\n# MAGIC\n# MAGIC 1. Open the Fabric workspace → **+ New** → **Mirrored Azure SQL Database**\n# MAGIC 2. Provide the Azure SQL connection details\n# MAGIC 3. Select tables: `dbo.Orders`, `dbo.CustomerActivity`\n# MAGIC 4. Fabric creates a managed Lakehouse with Delta tables automatically\n# MAGIC 5. Tables land under `lh_mirrored_casino.dbo_Orders` etc.\n# MAGIC\n# MAGIC NOTE: When using Fabric Mirroring the JDBC polling sections below are\n# MAGIC       NOT needed. This notebook's JDBC approach is a fallback for\n# MAGIC       environments where Mirroring is unavailable or requires custom logic.\n\nprint(\"Fabric Mirroring is the preferred method for Azure SQL Database.\")\nprint(\"See inline comments for portal configuration steps.\")\nprint(\"JDBC Change Tracking polling proceeds below as the programmatic alternative.\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-02-azure-sql-change-feed-c6",
    "type": "markdown",
    "source": "## 4. Read Change Feed — JDBC Change Tracking Polling\n\nChange Tracking returns only changed PKs plus metadata. We then join back\nto the source table to retrieve full row data for inserts/updates."
  },
  {
    "id": "streaming-02-azure-sql-change-feed-c7",
    "type": "code",
    "source": "def get_last_sync_version(table_name: str) -> int:\n    \"\"\"Read the last successfully processed CT version from the checkpoint.\"\"\"\n    version_path = f\"{CT_VERSION_DIR}/{table_name}_version.txt\"\n    try:\n        df = spark.read.text(version_path)\n        return int(df.collect()[0][0])\n    except Exception:\n        # First run — start from a safe baseline 24 hours behind current version\n        baseline_query = \"SELECT CHANGE_TRACKING_CURRENT_VERSION() - 1000 AS v\"\n        result = spark.read.jdbc(AZURE_SQL_JDBC_URL, f\"({baseline_query}) t\", properties=jdbc_properties)\n        return int(result.collect()[0][\"v\"])\n\n\ndef save_sync_version(table_name: str, version: int):\n    \"\"\"Persist the successfully processed CT version.\"\"\"\n    version_path = f\"{CT_VERSION_DIR}/{table_name}_version.txt\"\n    spark.createDataFrame([[str(version)]]).write.mode(\"overwrite\").text(version_path)\n\n\ndef read_changed_keys(table_name: str, schema_name: str, pk_col: str, last_version: int):\n    \"\"\"\n    Query CHANGETABLE to get all PKs modified since last_version.\n    Returns a DataFrame with pk, SYS_CHANGE_OPERATION, SYS_CHANGE_VERSION.\n    \"\"\"\n    ct_query = f\"\"\"\n        SELECT\n            CT.{pk_col},\n            CT.SYS_CHANGE_OPERATION  AS change_op,      -- I=Insert, U=Update, D=Delete\n            CT.SYS_CHANGE_VERSION    AS change_version,\n            CT.SYS_CHANGE_COLUMNS    AS changed_columns\n        FROM CHANGETABLE(CHANGES {schema_name}.{table_name}, {last_version}) AS CT\n    \"\"\"\n    return spark.read.jdbc(\n        AZURE_SQL_JDBC_URL,\n        f\"({ct_query}) change_keys\",\n        properties=jdbc_properties\n    )",
    "lang": "pyspark"
  },
  {
    "id": "streaming-02-azure-sql-change-feed-c8",
    "type": "markdown",
    "source": "## 5. Process Changes — Inserts, Updates, Deletes"
  },
  {
    "id": "streaming-02-azure-sql-change-feed-c9",
    "type": "code",
    "source": "# Schema for Orders (full row)\norders_schema = StructType([\n    StructField(\"OrderId\",         StringType(),       nullable=False),\n    StructField(\"CustomerId\",      StringType(),       nullable=True),\n    StructField(\"TableId\",         StringType(),       nullable=True),\n    StructField(\"GameType\",        StringType(),       nullable=True),\n    StructField(\"BetAmount\",       DecimalType(18, 2), nullable=True),\n    StructField(\"Outcome\",         StringType(),       nullable=True),  # WIN, LOSS, PUSH\n    StructField(\"OrderStatus\",     StringType(),       nullable=True),\n    StructField(\"CreatedAt\",       TimestampType(),    nullable=True),\n    StructField(\"UpdatedAt\",       TimestampType(),    nullable=True),\n])\n\n# Schema for CustomerActivity (full row)\ncustomer_activity_schema = StructType([\n    StructField(\"ActivityId\",      StringType(),       nullable=False),\n    StructField(\"CustomerId\",      StringType(),       nullable=True),\n    StructField(\"ActivityType\",    StringType(),       nullable=True),  # CHECK_IN, CHECK_OUT, COMP_REDEEM\n    StructField(\"LocationCode\",    StringType(),       nullable=True),\n    StructField(\"PointsEarned\",    IntegerType(),      nullable=True),\n    StructField(\"ActivityTs\",      TimestampType(),    nullable=True),\n])\n\n\ndef fetch_full_rows(table_name: str, schema_name: str, pk_col: str, changed_pks):\n    \"\"\"\n    Given a set of changed PKs, fetch the full current row from the source table.\n    Deletes will have no matching row — we identify them from change_op='D'.\n    \"\"\"\n    pk_list = \",\".join([f\"'{r[pk_col]}'\" for r in changed_pks.filter(F.col(\"change_op\") != \"D\").select(pk_col).collect()])\n    if not pk_list:\n        return spark.createDataFrame([], orders_schema)  # empty frame\n    full_row_query = f\"\"\"\n        SELECT * FROM {schema_name}.{table_name}\n        WHERE {pk_col} IN ({pk_list})\n    \"\"\"\n    return spark.read.jdbc(AZURE_SQL_JDBC_URL, f\"({full_row_query}) rows\", properties=jdbc_properties)\n\n\ndef process_table_changes(table_name: str, config: dict):\n    \"\"\"Full change-processing cycle for one CT-enabled table.\"\"\"\n    schema_name = config[\"schema\"]\n    pk_col      = config[\"pk\"]\n\n    last_version  = get_last_sync_version(table_name)\n    changed_keys  = read_changed_keys(table_name, schema_name, pk_col, last_version)\n    change_count  = changed_keys.count()\n\n    print(f\"[{table_name}] Found {change_count} changes since version {last_version}\")\n    if change_count == 0:\n        return\n\n    new_version = changed_keys.agg(F.max(\"change_version\")).collect()[0][0]\n\n    # Separate inserts/updates from deletes\n    upsert_keys  = changed_keys.filter(F.col(\"change_op\").isin(\"I\", \"U\"))\n    delete_keys  = changed_keys.filter(F.col(\"change_op\") == \"D\")\n\n    full_rows = (\n        fetch_full_rows(table_name, schema_name, pk_col, upsert_keys)\n        .withColumn(\"cdc_operation\",    F.lit(\"UPSERT\"))\n        .withColumn(\"source_table\",     F.lit(f\"{schema_name}.{table_name}\"))\n        .withColumn(\"ingested_at\",      F.current_timestamp())\n        .withColumn(\"ingestion_source\", F.lit(\"azure_sql_change_tracking\"))\n    )\n\n    # Soft-delete rows: stamp a deleted_at column rather than physical removal\n    delete_rows = (\n        delete_keys\n        .withColumnRenamed(pk_col, pk_col)\n        .withColumn(\"cdc_operation\",    F.lit(\"DELETE\"))\n        .withColumn(\"source_table\",     F.lit(f\"{schema_name}.{table_name}\"))\n        .withColumn(\"ingested_at\",      F.current_timestamp())\n        .withColumn(\"ingestion_source\", F.lit(\"azure_sql_change_tracking\"))\n        .withColumn(\"deleted_at\",       F.current_timestamp())\n    )\n\n    return full_rows, delete_rows, new_version",
    "lang": "pyspark"
  },
  {
    "id": "streaming-02-azure-sql-change-feed-c10",
    "type": "markdown",
    "source": "## 6. Write to Delta with MERGE for Upserts"
  },
  {
    "id": "streaming-02-azure-sql-change-feed-c11",
    "type": "code",
    "source": "def upsert_to_bronze(full_rows, delete_rows, table_name: str, pk_col: str, new_version: int):\n    \"\"\"\n    MERGE upsert into the Bronze Delta table.\n    - Matching PKs → UPDATE all columns\n    - New PKs      → INSERT\n    - Deleted PKs  → UPDATE with deleted_at timestamp (soft delete)\n    \"\"\"\n    # Ensure the Delta table exists (create on first run)\n    if not spark.catalog.tableExists(BRONZE_TABLE):\n        full_rows.write.format(\"delta\").partitionBy(\"source_table\").saveAsTable(BRONZE_TABLE)\n        save_sync_version(table_name, new_version)\n        return\n\n    bronze_delta = DeltaTable.forName(spark, BRONZE_TABLE)\n\n    if not full_rows.isEmpty():\n        (\n            bronze_delta.alias(\"target\")\n            .merge(\n                full_rows.alias(\"source\"),\n                f\"target.{pk_col} = source.{pk_col} AND target.source_table = source.source_table\"\n            )\n            .whenMatchedUpdateAll()\n            .whenNotMatchedInsertAll()\n            .execute()\n        )\n        print(f\"  Upserted {full_rows.count()} rows into {BRONZE_TABLE}\")\n\n    if not delete_rows.isEmpty():\n        (\n            bronze_delta.alias(\"target\")\n            .merge(\n                delete_rows.alias(\"source\"),\n                f\"target.{pk_col} = source.{pk_col} AND target.source_table = source.source_table\"\n            )\n            .whenMatchedUpdate(set={\"deleted_at\": \"source.deleted_at\", \"cdc_operation\": \"'DELETE'\"})\n            .execute()\n        )\n        print(f\"  Soft-deleted {delete_rows.count()} rows in {BRONZE_TABLE}\")\n\n    save_sync_version(table_name, new_version)\n\n\n# Execute the CT polling cycle for all configured tables\nfor table_name, config in CT_TABLES.items():\n    result = process_table_changes(table_name, config)\n    if result:\n        full_rows, delete_rows, new_version = result\n        upsert_to_bronze(full_rows, delete_rows, table_name, config[\"pk\"], new_version)",
    "lang": "pyspark"
  },
  {
    "id": "streaming-02-azure-sql-change-feed-c12",
    "type": "markdown",
    "source": "## 7. Monitoring"
  },
  {
    "id": "streaming-02-azure-sql-change-feed-c13",
    "type": "code",
    "source": "monitoring_sql = f\"\"\"\n-- Change counts by table and operation (last 24 hours)\nSELECT\n    source_table,\n    cdc_operation,\n    COUNT(*)           AS record_count,\n    MAX(ingested_at)   AS last_ingested,\n    COUNT(deleted_at)  AS soft_delete_count\nFROM {BRONZE_TABLE}\nWHERE ingested_at >= CURRENT_TIMESTAMP - INTERVAL 24 HOURS\nGROUP BY source_table, cdc_operation\nORDER BY source_table, cdc_operation;\n\n-- Detect duplicate PKs (should be zero for upsert-managed Bronze)\nSELECT source_table, OrderId, COUNT(*) AS dup_count\nFROM {BRONZE_TABLE}\nWHERE source_table = 'dbo.Orders'\nGROUP BY source_table, OrderId\nHAVING COUNT(*) > 1;\n\n-- Change Tracking version lag check (run on Azure SQL)\n-- SELECT\n--     CHANGE_TRACKING_CURRENT_VERSION()    AS current_version,\n--     CHANGE_TRACKING_MIN_VALID_VERSION(OBJECT_ID('dbo.Orders')) AS min_valid,\n--     CURRENT_TIMESTAMP                    AS check_time;\n\"\"\"\n\nprint(\"Monitoring SQL:\")\nprint(monitoring_sql)\n\n# Verify latest rows in Bronze\nif spark.catalog.tableExists(BRONZE_TABLE):\n    spark.sql(f\"\"\"\n        SELECT source_table, cdc_operation, COUNT(*) AS cnt, MAX(ingested_at) AS latest\n        FROM {BRONZE_TABLE}\n        GROUP BY source_table, cdc_operation\n        ORDER BY latest DESC\n    \"\"\").show(truncate=False)",
    "lang": "pyspark"
  }
];

const CELLS_STREAMING_03_COSMOS_DB_CHANGE_FEED: NotebookCell[] = [
  {
    "id": "streaming-03-cosmos-db-change-feed-c0",
    "type": "markdown",
    "source": "# Streaming: Cosmos DB Change Feed Processing\n\nReads the Azure Cosmos DB Change Feed using the Azure Cosmos DB Spark\nconnector and writes processed events to the Bronze Delta Lake table.\nThe change feed delivers every insert and update (not deletes by default)\nin partition-key order, enabling low-latency event streaming.\n\n**Architecture:** Cosmos DB → Change Feed → Spark Connector → Bronze Delta\n**Alternative:** Cosmos DB → Fabric Mirroring (GA) → Bronze Delta\n\n| Setting | Value |\n|---|---|\n| Source | Azure Cosmos DB for NoSQL (API) |\n| Containers | PlayerActivity (/playerId), SlotEvents (/machineId) |\n| Connector | azure-cosmos-spark_3-4_2-12 v4.x |\n| Sink | `lh_bronze.bronze_cdc_cosmos_db` |\n| Trigger | Continuous micro-batch (5s) |"
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c1",
    "type": "markdown",
    "source": "## 1. Configuration — Cosmos Connection & Container Setup"
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c2",
    "type": "code",
    "source": "import os\n\nfrom pyspark.sql import SparkSession\nfrom pyspark.sql import functions as F\nfrom pyspark.sql.types import (\n    ArrayType,\n    BooleanType,\n    DoubleType,\n    IntegerType,\n    LongType,\n    MapType,\n    StringType,\n    StructField,\n    StructType,\n    TimestampType,\n)\n\nspark = SparkSession.builder.getOrCreate()\n\n# ---------------------------------------------------------------------------\n# Cosmos DB connection configuration — all secrets via Key Vault\n# NOTE: In Fabric, use mssparkutils.credentials.getSecret() to avoid\n#       embedding connection strings in notebook source.\n# ---------------------------------------------------------------------------\ntry:\n    from notebookutils import mssparkutils\n    COSMOS_ENDPOINT = mssparkutils.credentials.getSecret(\n        \"kv-casino-poc\", \"cosmos-account-endpoint\"\n    )\n    COSMOS_KEY = mssparkutils.credentials.getSecret(\n        \"kv-casino-poc\", \"cosmos-account-key\"\n    )\n    CHECKPOINT_STORAGE = mssparkutils.credentials.getSecret(\n        \"kv-casino-poc\", \"adls-checkpoint-path\"\n    )\nexcept ImportError:\n    # Local / unit-test fallback\n    COSMOS_ENDPOINT = os.getenv(\"COSMOS_ENDPOINT\", \"https://<account>.documents.azure.com:443/\")\n    COSMOS_KEY      = os.getenv(\"COSMOS_KEY\", \"\")\n    CHECKPOINT_STORAGE = os.getenv(\"CHECKPOINT_PATH\", os.environ.get('CHECKPOINT_PATH_BASE', 'abfss://Files/checkpoints') + '')\n\nCOSMOS_DATABASE = \"CasinoDB\"\n\n# Container definitions: name → partition key path\nCOSMOS_CONTAINERS = {\n    \"PlayerActivity\": {\"partitionKey\": \"/playerId\",  \"throughput\": 4000},\n    \"SlotEvents\":     {\"partitionKey\": \"/machineId\", \"throughput\": 10000},\n}\n\n# Delta Lake target\nBRONZE_TABLE   = \"lh_bronze.bronze_cdc_cosmos_db\"\nCHECKPOINT_DIR = f\"{CHECKPOINT_STORAGE}/cdc_cosmos_db\"\n\n# NOTE: Fabric Mirroring for Cosmos DB (NoSQL) is generally available.\n#       The Mirroring approach is preferred for full fidelity without\n#       managing Spark connector versions. See Section 9 for setup details.",
    "lang": "pyspark"
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c3",
    "type": "markdown",
    "source": "## 2. Spark Cosmos Connector Setup\n\nThe Azure Cosmos DB Spark connector must be installed on the Fabric\nSpark environment before this notebook can run.\n\nInstallation:\n1. Fabric workspace → **Settings** → **Data Engineering/Science**\n2. Select the Spark environment → **Libraries** tab\n3. Add Maven coordinate: `com.azure.cosmos.spark:azure-cosmos-spark_3-4_2-12:4.35.0`\n4. Save and publish the environment"
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c4",
    "type": "code",
    "source": "# Cosmos Spark connector configuration dict — reused by readStream calls\ncosmos_config = {\n    \"spark.cosmos.accountEndpoint\": COSMOS_ENDPOINT,\n    \"spark.cosmos.accountKey\":      COSMOS_KEY,\n    \"spark.cosmos.database\":        COSMOS_DATABASE,\n    # Throughput control — limit RU/s consumed by Spark reads (optional)\n    \"spark.cosmos.throughputControl.enabled\":           \"true\",\n    \"spark.cosmos.throughputControl.targetThroughputThreshold\": \"0.75\",\n    # Change feed specific options\n    \"spark.cosmos.changeFeed.mode\":              \"Incremental\",  # or FullFidelity (preview)\n    \"spark.cosmos.changeFeed.startFrom\":         \"Now\",          # \"Beginning\" for full backfill\n    \"spark.cosmos.changeFeed.itemCountPerTriggerHint\": \"10000\",\n    # Connection tuning\n    \"spark.cosmos.read.maxItemCount\":            \"1000\",\n    \"spark.cosmos.connection.mode\":              \"Direct\",       # Gateway mode for restricted networks\n}\n\nprint(\"Cosmos Spark connector configuration loaded.\")\nprint(f\"  Endpoint: {COSMOS_ENDPOINT[:40]}...\")\nprint(f\"  Database: {COSMOS_DATABASE}\")\nprint(f\"  Containers: {list(COSMOS_CONTAINERS.keys())}\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c5",
    "type": "markdown",
    "source": "## 3. Read Change Feed with `spark.readStream.format(\"cosmos.oltp.changeFeed\")`\n\nThe change feed provides all mutations (inserts + updates) per partition.\nEach item is delivered in its full current form along with metadata fields\nprefixed with `_` (e.g., `_ts`, `_etag`, `_lsn`)."
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c6",
    "type": "code",
    "source": "# Schema for PlayerActivity container items\nplayer_activity_schema = StructType([\n    StructField(\"id\",             StringType(),  nullable=False),  # Cosmos item ID\n    StructField(\"playerId\",       StringType(),  nullable=False),  # Partition key\n    StructField(\"activityType\",   StringType(),  nullable=True),   # CHECK_IN, BET, COMP_REDEEM\n    StructField(\"locationCode\",   StringType(),  nullable=True),\n    StructField(\"gameCode\",       StringType(),  nullable=True),\n    StructField(\"amountWagered\",  DoubleType(),  nullable=True),\n    StructField(\"pointsEarned\",   IntegerType(), nullable=True),\n    StructField(\"sessionId\",      StringType(),  nullable=True),\n    StructField(\"deviceId\",       StringType(),  nullable=True),\n    StructField(\"eventTs\",        LongType(),    nullable=True),   # epoch ms (stored as number)\n    StructField(\"tags\",           ArrayType(StringType()), nullable=True),\n    # Cosmos system properties\n    StructField(\"_ts\",            LongType(),    nullable=True),   # last-modified epoch seconds\n    StructField(\"_etag\",          StringType(),  nullable=True),\n    StructField(\"_lsn\",           LongType(),    nullable=True),   # logical sequence number\n    StructField(\"_rid\",           StringType(),  nullable=True),\n])\n\n# Schema for SlotEvents container items\nslot_events_schema = StructType([\n    StructField(\"id\",             StringType(),  nullable=False),\n    StructField(\"machineId\",      StringType(),  nullable=False),  # Partition key\n    StructField(\"eventType\",      StringType(),  nullable=True),   # SPIN, JACKPOT, TILT, DOOR_OPEN\n    StructField(\"creditIn\",       DoubleType(),  nullable=True),\n    StructField(\"creditOut\",      DoubleType(),  nullable=True),\n    StructField(\"jackpotAmount\",  DoubleType(),  nullable=True),\n    StructField(\"denomination\",   DoubleType(),  nullable=True),\n    StructField(\"gameTitle\",      StringType(),  nullable=True),\n    StructField(\"floorZone\",      StringType(),  nullable=True),\n    StructField(\"eventTs\",        LongType(),    nullable=True),\n    StructField(\"_ts\",            LongType(),    nullable=True),\n    StructField(\"_etag\",          StringType(),  nullable=True),\n    StructField(\"_lsn\",           LongType(),    nullable=True),\n    StructField(\"_rid\",           StringType(),  nullable=True),\n])\n\n\ndef build_change_feed_stream(container_name: str, schema: StructType, container_checkpoint: str):\n    \"\"\"\n    Returns a structured streaming DataFrame sourced from the Cosmos DB change feed\n    for the specified container.\n    \"\"\"\n    container_config = {\n        **cosmos_config,\n        \"spark.cosmos.container\": container_name,\n    }\n\n    return (\n        spark.readStream\n        .format(\"cosmos.oltp.changeFeed\")\n        .options(**container_config)\n        .schema(schema)\n        .load()\n    )\n\n\n# Build change feed streams for each container\nplayer_activity_stream = build_change_feed_stream(\n    \"PlayerActivity\",\n    player_activity_schema,\n    f\"{CHECKPOINT_DIR}/player_activity\"\n)\n\nslot_events_stream = build_change_feed_stream(\n    \"SlotEvents\",\n    slot_events_schema,\n    f\"{CHECKPOINT_DIR}/slot_events\"\n)\n\nprint(\"Change feed streams created.\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c7",
    "type": "markdown",
    "source": "## 4. Multi-Partition Processing\n\nCosmos DB partitions are processed in parallel by Spark workers. The\nconnector maps each physical partition to a Spark task, so parallelism\nscales with container throughput and Spark executor count.\n\nNOTE: In Fabric Spark, executor count is controlled by the Spark pool\n      size. For high-throughput containers (>10K RU/s) use a Medium or\n      Large pool to match parallelism to partition count."
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c8",
    "type": "code",
    "source": "def enrich_change_feed(df, container_name: str):\n    \"\"\"\n    Add standard Bronze audit columns and normalise Cosmos metadata fields.\n    \"\"\"\n    return (\n        df\n        # Convert Cosmos _ts (epoch seconds) to a proper timestamp\n        .withColumn(\"cosmos_modified_at\",   F.to_timestamp(F.col(\"_ts\")))\n        # Convert application eventTs (epoch ms) to timestamp\n        .withColumn(\"event_timestamp\",\n            F.to_timestamp(F.from_unixtime(F.col(\"eventTs\") / 1000))\n        )\n        # Fabric Bronze audit columns\n        .withColumn(\"source_container\",     F.lit(container_name))\n        .withColumn(\"source_database\",      F.lit(COSMOS_DATABASE))\n        .withColumn(\"ingested_at\",          F.current_timestamp())\n        .withColumn(\"ingestion_source\",     F.lit(\"cosmos_db_change_feed\"))\n        # Partition date for Delta partitioning\n        .withColumn(\"event_date\",           F.to_date(F.col(\"event_timestamp\")))\n        # Lag metric: seconds between event and ingestion\n        .withColumn(\"ingestion_lag_s\",\n            F.unix_timestamp(F.current_timestamp()) - F.col(\"_ts\")\n        )\n        # Drop raw epoch fields after conversion\n        .drop(\"eventTs\")\n    )\n\n\n# Apply enrichment to both streams\nplayer_activity_enriched = enrich_change_feed(player_activity_stream, \"PlayerActivity\")\nslot_events_enriched      = enrich_change_feed(slot_events_stream,     \"SlotEvents\")\n\nprint(\"Enrichment transforms applied.\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c9",
    "type": "markdown",
    "source": "## 5. Write to Delta Lake"
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c10",
    "type": "code",
    "source": "# NOTE: Two separate writeStream queries are used — one per container — so\n#       each has its own checkpoint location and can be managed independently.\n#       Fabric supports up to 50 concurrent streaming queries per workspace.\n\n# PlayerActivity stream → Bronze Delta\nplayer_query = (\n    player_activity_enriched\n    .writeStream\n    .format(\"delta\")\n    .outputMode(\"append\")\n    .option(\"checkpointLocation\", f\"{CHECKPOINT_DIR}/player_activity\")\n    .option(\"mergeSchema\", \"true\")\n    .partitionBy(\"source_container\", \"event_date\")\n    .trigger(processingTime=\"5 seconds\")\n    .toTable(BRONZE_TABLE)\n)\n\n# SlotEvents stream → Bronze Delta (same table, different partition)\nslot_query = (\n    slot_events_enriched\n    .writeStream\n    .format(\"delta\")\n    .outputMode(\"append\")\n    .option(\"checkpointLocation\", f\"{CHECKPOINT_DIR}/slot_events\")\n    .option(\"mergeSchema\", \"true\")\n    .partitionBy(\"source_container\", \"event_date\")\n    .trigger(processingTime=\"5 seconds\")\n    .toTable(BRONZE_TABLE)\n)\n\nprint(f\"PlayerActivity query started: {player_query.id}\")\nprint(f\"SlotEvents query started:     {slot_query.id}\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c11",
    "type": "markdown",
    "source": "## 6. Monitoring"
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c12",
    "type": "code",
    "source": "monitoring_sql = f\"\"\"\n-- Event throughput by container (last 15 minutes)\nSELECT\n    source_container,\n    COUNT(*)                                AS event_count,\n    AVG(ingestion_lag_s)                    AS avg_lag_seconds,\n    MAX(ingestion_lag_s)                    AS max_lag_seconds,\n    MIN(event_timestamp)                    AS earliest_event,\n    MAX(event_timestamp)                    AS latest_event,\n    MAX(ingested_at)                        AS last_ingested_at\nFROM {BRONZE_TABLE}\nWHERE ingested_at >= CURRENT_TIMESTAMP - INTERVAL 15 MINUTES\nGROUP BY source_container;\n\n-- PlayerActivity event type distribution\nSELECT\n    activityType,\n    COUNT(*)    AS event_count,\n    AVG(amountWagered) AS avg_wagered\nFROM {BRONZE_TABLE}\nWHERE source_container = 'PlayerActivity'\n  AND event_date = CURRENT_DATE\nGROUP BY activityType\nORDER BY event_count DESC;\n\n-- Slot machine jackpot events (last hour)\nSELECT\n    machineId,\n    floorZone,\n    jackpotAmount,\n    event_timestamp,\n    ingestion_lag_s\nFROM {BRONZE_TABLE}\nWHERE source_container  = 'SlotEvents'\n  AND eventType         = 'JACKPOT'\n  AND ingested_at >= CURRENT_TIMESTAMP - INTERVAL 1 HOUR\nORDER BY event_timestamp DESC;\n\n-- Detect high ingestion lag (SLA breach > 10 seconds)\nSELECT\n    source_container,\n    COUNT(*) AS breach_count,\n    MAX(ingestion_lag_s) AS max_lag_s\nFROM {BRONZE_TABLE}\nWHERE ingestion_lag_s > 10\n  AND ingested_at >= CURRENT_TIMESTAMP - INTERVAL 1 HOUR\nGROUP BY source_container;\n\"\"\"\n\nprint(\"Monitoring SQL:\")\nprint(monitoring_sql)\n\n# Live stream progress\nfor q_name, q in [(\"PlayerActivity\", player_query), (\"SlotEvents\", slot_query)]:\n    if q.isActive:\n        p = q.lastProgress\n        if p:\n            print(f\"\\n[{q_name}]\")\n            print(f\"  Input rows/s   : {p.get('inputRowsPerSecond', 'N/A')}\")\n            print(f\"  Processed rows/s: {p.get('processedRowsPerSecond', 'N/A')}\")\n            print(f\"  Batch duration : {p.get('batchDuration', 'N/A')} ms\")\n            print(f\"  Sources lag    : {p.get('sources', [{}])[0].get('endOffset', 'N/A')}\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c13",
    "type": "code",
    "source": "# MAGIC %md\n# MAGIC ## 7. Fabric Mirroring for Cosmos DB (Alternative — Recommended for GA)\n# MAGIC\n# MAGIC Microsoft Fabric Database Mirroring supports Azure Cosmos DB for NoSQL\n# MAGIC as a generally available source. It replicates the change feed automatically\n# MAGIC and lands data in a managed Lakehouse as Delta tables, without requiring\n# MAGIC this notebook or Spark connector management.\n# MAGIC\n# MAGIC **Setup steps (Fabric portal):**\n# MAGIC 1. **+ New** → **Mirrored Azure Cosmos DB**\n# MAGIC 2. Enter AccountEndpoint and AccountKey (or use a linked service)\n# MAGIC 3. Select database `CasinoDB` and containers `PlayerActivity`, `SlotEvents`\n# MAGIC 4. Fabric creates `lh_mirrored_casinodb.PlayerActivity` etc. automatically\n# MAGIC 5. The Delta tables are directly queryable with Direct Lake from Power BI\n# MAGIC\n# MAGIC NOTE: Mirroring handles schema evolution, partition management, and\n# MAGIC       checkpointing automatically. Use this notebook only when custom\n# MAGIC       transformation logic is needed at ingestion time.\n\nprint(\"Fabric Mirroring for Cosmos DB is available via the Fabric portal.\")\nprint(\"See inline comments above for configuration steps.\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c14",
    "type": "markdown",
    "source": "## 8. Cleanup — Stop Streaming Queries"
  },
  {
    "id": "streaming-03-cosmos-db-change-feed-c15",
    "type": "code",
    "source": "def stop_cosmos_streams():\n    \"\"\"Gracefully stop all Cosmos change feed streaming queries.\"\"\"\n    stopped = 0\n    for q in spark.streams.active:\n        q.stop()\n        print(f\"Stopped: {q.id}\")\n        stopped += 1\n    print(f\"Total queries stopped: {stopped}\")\n\n# Uncomment to stop all active queries:\n# stop_cosmos_streams()\n\n# Status summary\nactive_queries = spark.streams.active\nprint(f\"Active streaming queries: {len(active_queries)}\")\nfor q in active_queries:\n    print(f\"  [{q.id}] status={q.status['message']} | active={q.isActive}\")",
    "lang": "pyspark"
  }
];

const CELLS_STREAMING_04_IBM_DB2_CDC: NotebookCell[] = [
  {
    "id": "streaming-04-ibm-db2-cdc-c0",
    "type": "markdown",
    "source": "# Streaming: IBM DB2 CDC via JDBC\n\nIngests change data from IBM DB2 legacy systems (LUW on-premises and z/OS\nmainframe) using JDBC batch polling of DB2 ASN (Replication) staging tables.\nHandles EBCDIC encoding, packed decimal data types, and mainframe-specific\ndate/time formats before writing to Bronze Delta Lake.\n\n**Architecture:** DB2 → ASN Replication → JDBC Polling → SHIR → Bronze Delta\n\n| Setting | Value |\n|---|---|\n| Source (LUW) | IBM DB2 LUW 11.5+ (Linux/Unix/Windows) |\n| Source (z/OS) | IBM DB2 for z/OS v12+ |\n| JDBC Driver | IBM DB2 JCC Driver 4.x (db2jcc4.jar) |\n| Tables | CASINO.LEGACY_TRANSACTIONS, CASINO.PLAYER_HISTORY |\n| Sink | `lh_bronze.bronze_cdc_ibm_db2` |\n| Write Mode | Append (Bronze immutable log) |"
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c1",
    "type": "markdown",
    "source": "## 1. Configuration — JDBC URL & Driver"
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c2",
    "type": "code",
    "source": "import os\n\nfrom pyspark.sql import SparkSession\nfrom pyspark.sql import functions as F\nfrom pyspark.sql.types import (\n    BooleanType,\n    DateType,\n    DecimalType,\n    IntegerType,\n    LongType,\n    StringType,\n    StructField,\n    StructType,\n    TimestampType,\n)\n\nspark = SparkSession.builder.getOrCreate()\n\n# ---------------------------------------------------------------------------\n# DB2 connection configuration — all secrets via Key Vault\n# NOTE: In Fabric, use mssparkutils.credentials.getSecret() to avoid\n#       embedding credentials in notebook source.\n# ---------------------------------------------------------------------------\ntry:\n    from notebookutils import mssparkutils\n    DB2_HOST     = mssparkutils.credentials.getSecret(\"kv-casino-poc\", \"db2-host\")\n    DB2_PORT     = mssparkutils.credentials.getSecret(\"kv-casino-poc\", \"db2-port\")\n    DB2_DATABASE = mssparkutils.credentials.getSecret(\"kv-casino-poc\", \"db2-database\")\n    DB2_USER     = mssparkutils.credentials.getSecret(\"kv-casino-poc\", \"db2-username\")\n    DB2_PASSWORD = mssparkutils.credentials.getSecret(\"kv-casino-poc\", \"db2-password\")\n    CHECKPOINT_STORAGE = mssparkutils.credentials.getSecret(\n        \"kv-casino-poc\", \"adls-checkpoint-path\"\n    )\nexcept ImportError:\n    DB2_HOST     = os.getenv(\"DB2_HOST\", \"<db2-host>\")\n    DB2_PORT     = os.getenv(\"DB2_PORT\", \"50000\")\n    DB2_DATABASE = os.getenv(\"DB2_DATABASE\", \"CASINODB\")\n    DB2_USER     = os.getenv(\"DB2_USER\", \"\")\n    DB2_PASSWORD = os.getenv(\"DB2_PASSWORD\", \"\")\n    CHECKPOINT_STORAGE = os.getenv(\"CHECKPOINT_PATH\", os.environ.get('CHECKPOINT_PATH_BASE', 'abfss://Files/checkpoints') + '')\n\n# DB2 LUW JDBC URL (standard TCP/IP port 50000)\nDB2_LUW_JDBC_URL = f\"jdbc:db2://{DB2_HOST}:{DB2_PORT}/{DB2_DATABASE}\"\n\n# DB2 for z/OS JDBC URL (DB2 Connect gateway, port 446 is standard for z/OS)\n# NOTE: z/OS uses a different port and often requires SSL certificates from\n#       the mainframe security administrator.\nDB2_ZOS_JDBC_URL = (\n    f\"jdbc:db2://{DB2_HOST}:446/{DB2_DATABASE}\"\n    f\":sslConnection=true;sslTrustStoreLocation=/mnt/certs/db2zos.jks;\"\n    f\"sslTrustStorePassword=${{DB2_ZOS_TRUSTSTORE_PASSWORD}};\"\n)\n\n# JDBC properties — common to LUW and z/OS connections\njdbc_properties = {\n    \"user\":               DB2_USER,\n    \"password\":           DB2_PASSWORD,\n    \"driver\":             \"com.ibm.db2.jcc.DB2Driver\",\n    \"fetchSize\":          \"10000\",    # rows per JDBC fetch batch\n    \"isolationLevel\":     \"READ_UNCOMMITTED\",  # avoid lock contention on high-volume tables\n    \"currentSchema\":      \"CASINO\",\n    \"progressiveStreaming\": \"2\",      # DB2 JCC progressive streaming: reduce memory pressure\n}\n\n# Target table names in DB2 (schema-qualified)\nDB2_LEGACY_TRANSACTIONS = \"CASINO.LEGACY_TRANSACTIONS\"\nDB2_PLAYER_HISTORY      = \"CASINO.PLAYER_HISTORY\"\n\n# ASN replication staging table (created by DB2 InfoSphere CDC / Q-Capture)\nDB2_ASN_STAGING_TABLE   = \"ASNTB.CDC_STAGING\"\n\n# Delta Lake target\nBRONZE_TABLE   = \"lh_bronze.bronze_cdc_ibm_db2\"\nCHECKPOINT_DIR = f\"{CHECKPOINT_STORAGE}/cdc_ibm_db2\"\nWATERMARK_DIR  = f\"{CHECKPOINT_STORAGE}/db2_watermarks\"\n\nprint(f\"DB2 LUW JDBC URL : {DB2_LUW_JDBC_URL}\")\nprint(f\"DB2 z/OS JDBC URL: {DB2_ZOS_JDBC_URL[:60]}...\")\nprint(f\"Bronze table     : {BRONZE_TABLE}\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c3",
    "type": "markdown",
    "source": "## 2. DB2 LUW vs z/OS Differences\n\n| Feature | DB2 LUW | DB2 for z/OS |\n|---|---|---|\n| Default encoding | UTF-8 | EBCDIC (CP037 / CP1047) |\n| Date format | ISO (YYYY-MM-DD) | ISO or Packed (PIC 9) |\n| Decimal type | DECIMAL(p,s) native | PACKED DECIMAL in COBOL blobs |\n| JDBC port | 50000 | 446 (DB2 Connect) |\n| Max row size | 32,677 bytes | 32,764 bytes |\n| LOB handling | Native JDBC LOB | Requires progressiveStreaming=2 |\n| Schemas | Case-insensitive | UPPERCASE enforced |\n| Timestamp precision | microseconds | microseconds (v12+) |\n| ROWID | Not applicable | ROWID column exists |\n| Concurrency | Optimistic via RRSAF | DRDA / DB2 Connect |"
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c4",
    "type": "markdown",
    "source": "## 3. JDBC Connection Setup & Driver Installation\n\n**Install the IBM DB2 JCC driver on the Fabric Spark environment:**\n1. Download `db2jcc4.jar` from IBM Fix Central (requires IBM entitlement)\n2. Upload the JAR to your ADLS Gen2 storage: `abfss://libs@<storage>.dfs.core.windows.net/jdbc/db2jcc4.jar`\n3. In Fabric workspace → **Settings** → Spark environment → **Libraries** → **Custom libraries**\n4. Add the JAR file path\n5. NOTE: IBM DB2 JCC is not available on Maven Central; manual JAR installation is required."
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c5",
    "type": "code",
    "source": "def test_db2_connection(jdbc_url: str, properties: dict) -> bool:\n    \"\"\"\n    Validates DB2 JDBC connectivity by querying SYSIBM.SYSDUMMY1\n    (the DB2 equivalent of Oracle's DUAL table).\n    \"\"\"\n    try:\n        test_df = spark.read.jdbc(\n            url=jdbc_url,\n            table=\"(SELECT 1 AS ping FROM SYSIBM.SYSDUMMY1) test\",\n            properties=properties\n        )\n        test_df.collect()\n        print(f\"DB2 connection OK: {jdbc_url[:50]}...\")\n        return True\n    except Exception as e:\n        print(f\"DB2 connection FAILED: {e}\")\n        return False\n\n# Test connectivity before running the full pipeline\n# luw_ok = test_db2_connection(DB2_LUW_JDBC_URL, jdbc_properties)",
    "lang": "pyspark"
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c6",
    "type": "markdown",
    "source": "## 4. Read CDC / ASN Replication Tables\n\nIBM DB2 CDC is typically implemented via:\n- **IBM InfoSphere Data Replication (Q-Capture/Q-Apply)** — enterprise CDC\n- **DB2 SQL Replication (Capture/Apply)** — native DB2 CDC, writes to ASN staging tables\n- **Direct JDBC polling** — watermark-based incremental extraction (fallback)\n\nThis notebook uses watermark-based JDBC polling against the source tables\nand optionally reads ASN staging tables if DB2 Replication is configured."
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c7",
    "type": "code",
    "source": "# Schema for CASINO.LEGACY_TRANSACTIONS (DB2 LUW source)\nlegacy_transactions_schema = StructType([\n    StructField(\"TRANS_ID\",       StringType(),       nullable=False),  # CHAR(36) — UUID\n    StructField(\"PLAYER_ID\",      StringType(),       nullable=True),   # CHAR(20)\n    StructField(\"MACHINE_ID\",     StringType(),       nullable=True),   # CHAR(15)\n    StructField(\"TRANS_AMOUNT\",   DecimalType(15, 2), nullable=True),   # DECIMAL(15,2)\n    StructField(\"TRANS_TYPE\",     StringType(),       nullable=True),   # CHAR(10): BET, WIN, COMP\n    StructField(\"GAME_CODE\",      StringType(),       nullable=True),   # VARCHAR(20)\n    StructField(\"TRANS_DATE\",     DateType(),         nullable=True),   # DATE\n    StructField(\"TRANS_TIME\",     StringType(),       nullable=True),   # TIME stored as VARCHAR on some systems\n    StructField(\"TRANS_TS\",       TimestampType(),    nullable=True),   # TIMESTAMP(6)\n    StructField(\"STATUS_CODE\",    StringType(),       nullable=True),   # CHAR(2): AC, VO, PE\n    StructField(\"CAGE_ID\",        StringType(),       nullable=True),   # CHAR(10)\n    StructField(\"SHIFT_CODE\",     StringType(),       nullable=True),   # CHAR(1): D, S, G\n    StructField(\"LAST_UPDATED\",   TimestampType(),    nullable=True),   # Watermark column\n])\n\n# Schema for CASINO.PLAYER_HISTORY (DB2 z/OS source — note uppercase enforcement)\nplayer_history_schema = StructType([\n    StructField(\"PLAYER_ID\",      StringType(),       nullable=False),  # CHAR(20)\n    StructField(\"VISIT_DATE\",     DateType(),         nullable=True),   # DATE\n    StructField(\"TOTAL_WAGERED\",  DecimalType(18, 2), nullable=True),   # DECIMAL(18,2)\n    StructField(\"TOTAL_WON\",      DecimalType(18, 2), nullable=True),\n    StructField(\"POINTS_EARNED\",  IntegerType(),      nullable=True),   # INTEGER\n    StructField(\"TIER_CODE\",      StringType(),       nullable=True),   # CHAR(2): BR, SL, GO, PL\n    StructField(\"EXCLUSION_FLAG\", StringType(),       nullable=True),   # CHAR(1): Y/N\n    StructField(\"RECORD_TS\",      TimestampType(),    nullable=True),   # Watermark column\n    StructField(\"ROWID_COL\",      StringType(),       nullable=True),   # DB2 z/OS ROWID (string representation)\n])\n\n\ndef get_last_watermark(table_name: str) -> str:\n    \"\"\"Read the last successfully processed watermark timestamp.\"\"\"\n    wm_path = f\"{WATERMARK_DIR}/{table_name.replace('.', '_')}_watermark.txt\"\n    try:\n        df = spark.read.text(wm_path)\n        wm = df.collect()[0][0]\n        print(f\"[{table_name}] Last watermark: {wm}\")\n        return wm\n    except Exception:\n        # First run: start 7 days back\n        default_wm = \"2024-01-01 00:00:00\"\n        print(f\"[{table_name}] No watermark found, using default: {default_wm}\")\n        return default_wm\n\n\ndef save_watermark(table_name: str, watermark: str):\n    \"\"\"Persist the successfully processed watermark.\"\"\"\n    wm_path = f\"{WATERMARK_DIR}/{table_name.replace('.', '_')}_watermark.txt\"\n    spark.createDataFrame([[watermark]]).write.mode(\"overwrite\").text(wm_path)\n    print(f\"[{table_name}] Saved watermark: {watermark}\")\n\n\ndef read_db2_incremental(\n    jdbc_url: str,\n    table_name: str,\n    watermark_col: str,\n    last_watermark: str,\n    schema: StructType,\n    partition_col: str = None,\n    num_partitions: int = 8,\n) -> \"DataFrame\":\n    \"\"\"\n    Read incremental rows from DB2 since the last watermark.\n    Uses JDBC partitioning for parallel reads on large tables.\n    \"\"\"\n    query = f\"\"\"\n        SELECT * FROM {table_name}\n        WHERE {watermark_col} > TIMESTAMP('{last_watermark}')\n          AND {watermark_col} <= CURRENT TIMESTAMP\n        ORDER BY {watermark_col} ASC\n        FETCH FIRST 500000 ROWS ONLY\n    \"\"\"\n    # NOTE: DB2 uses FETCH FIRST n ROWS ONLY instead of SQL LIMIT\n\n    read_options = {**jdbc_properties}\n\n    if partition_col:\n        # Parallel JDBC read — requires a numeric/date lower/upper bound\n        return (\n            spark.read\n            .schema(schema)\n            .jdbc(\n                url=jdbc_url,\n                table=f\"({query}) incremental\",\n                column=partition_col,\n                lowerBound=0,\n                upperBound=9999999,\n                numPartitions=num_partitions,\n                properties=read_options,\n            )\n        )\n    else:\n        return (\n            spark.read\n            .schema(schema)\n            .jdbc(url=jdbc_url, table=f\"({query}) incremental\", properties=read_options)\n        )",
    "lang": "pyspark"
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c8",
    "type": "markdown",
    "source": "## 5. Handle EBCDIC Encoding (z/OS)\n\nDB2 for z/OS stores character data in EBCDIC by default. The IBM DB2\nJCC driver handles EBCDIC→Unicode conversion transparently for standard\nCHAR/VARCHAR columns. However, BLOB columns containing packed COBOL data\nrequire explicit decoding via Python's `codecs` library.\n\nNOTE: Ensure the JCC driver `currentStringEncoding` property matches the\n      CCSID configured on the z/OS subsystem (typically CCSID 037 or 1047)."
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c9",
    "type": "code",
    "source": "import codecs\n\nfrom pyspark.sql.functions import udf\nfrom pyspark.sql.types import StringType as ST\n\n\ndef decode_ebcdic_blob(blob_bytes: bytes, ccsid: str = \"cp037\") -> str:\n    \"\"\"\n    Decode an EBCDIC-encoded byte array to a UTF-8 Python string.\n    CCSID 037 = US EBCDIC (most common in North American mainframes)\n    CCSID 1047 = Latin-1 Open Systems (used in some DB2 z/OS configs)\n    \"\"\"\n    if blob_bytes is None:\n        return None\n    try:\n        if isinstance(blob_bytes, (bytes, bytearray)):\n            return blob_bytes.decode(ccsid).strip()\n        return str(blob_bytes).strip()\n    except (UnicodeDecodeError, LookupError):\n        # Fall back to UTF-8 if EBCDIC decode fails (LUW data received in error)\n        return blob_bytes.decode(\"utf-8\", errors=\"replace\").strip()\n\n\n# Register as a Spark UDF for use in DataFrame transformations\ndecode_ebcdic_udf = udf(decode_ebcdic_blob, ST())\n\n\ndef handle_packed_decimal(df, packed_col: str, precision: int = 15, scale: int = 2):\n    \"\"\"\n    DB2 z/OS COBOL packed decimal (COMP-3) fields stored as raw bytes require\n    unpacking. The JCC driver handles standard DECIMAL columns natively;\n    this UDF handles edge cases where COBOL copybooks expose raw COMP-3 bytes.\n\n    For standard DB2 DECIMAL(p,s) columns JCC translates automatically —\n    only use this for BLOB-embedded COBOL structures.\n    \"\"\"\n    # NOTE: Standard DB2 DECIMAL columns are handled by the JCC driver.\n    #       Only use this transform for BLOB payloads containing COBOL COMP-3.\n    return df.withColumn(\n        packed_col,\n        F.col(packed_col).cast(DecimalType(precision, scale))\n    )",
    "lang": "pyspark"
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c10",
    "type": "markdown",
    "source": "## 6. Data Type Mapping — DB2 to Spark"
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c11",
    "type": "code",
    "source": "# DB2 → Spark type mapping reference\nDB2_SPARK_TYPE_MAP = {\n    # Numeric types\n    \"SMALLINT\":          \"ShortType\",\n    \"INTEGER\":           \"IntegerType\",\n    \"BIGINT\":            \"LongType\",\n    \"DECIMAL(p,s)\":      \"DecimalType(p,s)\",  # maps directly\n    \"NUMERIC(p,s)\":      \"DecimalType(p,s)\",\n    \"REAL\":              \"FloatType\",\n    \"DOUBLE\":            \"DoubleType\",\n    \"DECFLOAT(16)\":      \"DoubleType\",        # approximate mapping\n    \"DECFLOAT(34)\":      \"DecimalType(38,10)\", # high-precision fallback\n    # String types\n    \"CHAR(n)\":           \"StringType\",         # fixed-length → trimmed string\n    \"VARCHAR(n)\":        \"StringType\",\n    \"LONG VARCHAR\":      \"StringType\",\n    \"CLOB\":              \"StringType\",         # JCC streams LOBs as String\n    # Date/time types\n    \"DATE\":              \"DateType\",\n    \"TIME\":              \"StringType\",         # HH:MM:SS stored as string\n    \"TIMESTAMP(p)\":      \"TimestampType\",      # microsecond precision\n    # Binary types\n    \"BLOB\":              \"BinaryType\",\n    \"VARBINARY(n)\":      \"BinaryType\",\n    \"CHAR(n) FOR BIT DATA\": \"BinaryType\",\n    # Boolean (DB2 has no native BOOLEAN — simulated as CHAR(1) Y/N or SMALLINT 0/1)\n    \"CHAR(1) Y/N\":       \"BooleanType (after Y→true/N→false UDF)\",\n}\n\nprint(\"DB2 → Spark type mapping:\")\nfor db2_type, spark_type in DB2_SPARK_TYPE_MAP.items():\n    print(f\"  {db2_type:<30} → {spark_type}\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c12",
    "type": "markdown",
    "source": "## 7. Run Incremental Extract & Write to Delta Lake"
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c13",
    "type": "code",
    "source": "def process_db2_table(\n    jdbc_url: str,\n    table_name: str,\n    watermark_col: str,\n    schema: StructType,\n    source_system: str,   # \"db2_luw\" or \"db2_zos\"\n):\n    \"\"\"Full incremental extract cycle for one DB2 table.\"\"\"\n    last_wm = get_last_watermark(table_name)\n\n    raw_df = read_db2_incremental(\n        jdbc_url=jdbc_url,\n        table_name=table_name,\n        watermark_col=watermark_col,\n        last_watermark=last_wm,\n        schema=schema,\n    )\n\n    row_count = raw_df.count()\n    print(f\"[{table_name}] Extracted {row_count} rows since {last_wm}\")\n    if row_count == 0:\n        return 0\n\n    # Add Bronze audit columns\n    enriched_df = (\n        raw_df\n        # Normalise DB2 CHAR(1) Y/N boolean columns\n        .withColumn(\"exclusion_flag_bool\",\n            F.when(F.col(\"EXCLUSION_FLAG\") == \"Y\", F.lit(True))\n             .when(F.col(\"EXCLUSION_FLAG\") == \"N\", F.lit(False))\n             .otherwise(F.lit(None).cast(BooleanType()))\n            if \"EXCLUSION_FLAG\" in [c.name for c in raw_df.schema] else F.lit(None).cast(BooleanType())\n        )\n        # Trim trailing spaces from CHAR(n) columns (DB2 pads with spaces)\n        .withColumn(\"TRANS_TYPE\",\n            F.trim(F.col(\"TRANS_TYPE\"))\n            if \"TRANS_TYPE\" in [c.name for c in raw_df.schema] else F.lit(None)\n        )\n        # Fabric Bronze audit columns\n        .withColumn(\"source_table\",      F.lit(table_name))\n        .withColumn(\"source_system\",     F.lit(source_system))\n        .withColumn(\"ingested_at\",       F.current_timestamp())\n        .withColumn(\"ingestion_source\",  F.lit(\"ibm_db2_jdbc_cdc\"))\n        .withColumn(\"extraction_date\",   F.to_date(F.current_timestamp()))\n    )\n\n    # Append to Bronze Delta table\n    (\n        enriched_df.write\n        .format(\"delta\")\n        .mode(\"append\")\n        .option(\"mergeSchema\", \"true\")\n        .partitionBy(\"source_table\", \"extraction_date\")\n        .saveAsTable(BRONZE_TABLE)\n    )\n\n    # Update watermark to the max LAST_UPDATED / RECORD_TS seen in this batch\n    new_wm = raw_df.agg(F.max(watermark_col)).collect()[0][0]\n    if new_wm:\n        save_watermark(table_name, str(new_wm))\n\n    print(f\"[{table_name}] Wrote {row_count} rows to {BRONZE_TABLE}. New watermark: {new_wm}\")\n    return row_count\n\n\n# Run extract for DB2 LUW — LEGACY_TRANSACTIONS\nluw_count = process_db2_table(\n    jdbc_url=DB2_LUW_JDBC_URL,\n    table_name=DB2_LEGACY_TRANSACTIONS,\n    watermark_col=\"LAST_UPDATED\",\n    schema=legacy_transactions_schema,\n    source_system=\"db2_luw\",\n)\n\n# Run extract for DB2 z/OS — PLAYER_HISTORY\n# NOTE: For z/OS, switch to DB2_ZOS_JDBC_URL and ensure JCC SSL cert is configured\nzos_count = process_db2_table(\n    jdbc_url=DB2_LUW_JDBC_URL,  # Replace with DB2_ZOS_JDBC_URL for z/OS target\n    table_name=DB2_PLAYER_HISTORY,\n    watermark_col=\"RECORD_TS\",\n    schema=player_history_schema,\n    source_system=\"db2_zos\",\n)\n\nprint(f\"\\nExtraction summary:\")\nprint(f\"  {DB2_LEGACY_TRANSACTIONS}: {luw_count} rows\")\nprint(f\"  {DB2_PLAYER_HISTORY}:       {zos_count} rows\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c14",
    "type": "markdown",
    "source": "## 8. Monitoring"
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c15",
    "type": "code",
    "source": "monitoring_sql = f\"\"\"\n-- Extraction volume by source table and date (last 7 days)\nSELECT\n    source_table,\n    source_system,\n    extraction_date,\n    COUNT(*)            AS row_count,\n    MAX(ingested_at)    AS last_ingested_at\nFROM {BRONZE_TABLE}\nWHERE ingested_at >= CURRENT_TIMESTAMP - INTERVAL 7 DAYS\nGROUP BY source_table, source_system, extraction_date\nORDER BY extraction_date DESC, source_table;\n\n-- Detect potential duplicate ingestion (same TRANS_ID ingested multiple times)\nSELECT\n    TRANS_ID,\n    COUNT(*)    AS ingestion_count,\n    MIN(ingested_at) AS first_ingested,\n    MAX(ingested_at) AS last_ingested\nFROM {BRONZE_TABLE}\nWHERE source_table = 'CASINO.LEGACY_TRANSACTIONS'\nGROUP BY TRANS_ID\nHAVING COUNT(*) > 1\nORDER BY ingestion_count DESC\nLIMIT 20;\n\n-- DB2 z/OS: monitor EBCDIC decode failures (null values in expected non-null columns)\nSELECT\n    extraction_date,\n    COUNT(*) AS total_rows,\n    COUNT(PLAYER_ID) AS non_null_player_id,\n    COUNT(TRANS_ID)  AS non_null_trans_id,\n    (COUNT(*) - COUNT(TRANS_ID)) AS potential_decode_failures\nFROM {BRONZE_TABLE}\nWHERE source_system = 'db2_zos'\n  AND extraction_date = CURRENT_DATE\nGROUP BY extraction_date;\n\n-- Transaction amount distribution (sanity check for packed decimal conversion)\nSELECT\n    source_system,\n    ROUND(PERCENTILE_CONT(0.25) WITHIN GROUP (ORDER BY TRANS_AMOUNT), 2) AS p25_amount,\n    ROUND(PERCENTILE_CONT(0.50) WITHIN GROUP (ORDER BY TRANS_AMOUNT), 2) AS p50_amount,\n    ROUND(PERCENTILE_CONT(0.75) WITHIN GROUP (ORDER BY TRANS_AMOUNT), 2) AS p75_amount,\n    ROUND(PERCENTILE_CONT(0.99) WITHIN GROUP (ORDER BY TRANS_AMOUNT), 2) AS p99_amount,\n    MAX(TRANS_AMOUNT) AS max_amount\nFROM {BRONZE_TABLE}\nWHERE source_table = 'CASINO.LEGACY_TRANSACTIONS'\n  AND extraction_date = CURRENT_DATE\nGROUP BY source_system;\n\"\"\"\n\nprint(\"Monitoring SQL:\")\nprint(monitoring_sql)\n\n# Quick Bronze validation\nif spark.catalog.tableExists(BRONZE_TABLE):\n    spark.sql(f\"\"\"\n        SELECT\n            source_table,\n            source_system,\n            COUNT(*)          AS total_rows,\n            MAX(ingested_at)  AS latest_ingestion\n        FROM {BRONZE_TABLE}\n        GROUP BY source_table, source_system\n        ORDER BY latest_ingestion DESC\n    \"\"\").show(truncate=False)\nelse:\n    print(f\"Table {BRONZE_TABLE} does not yet exist — run extraction first.\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-04-ibm-db2-cdc-c16",
    "type": "code",
    "source": "# MAGIC %md\n# MAGIC ## 9. Schedule as Fabric Data Pipeline Activity\n# MAGIC\n# MAGIC For near-real-time DB2 ingestion, schedule this notebook via a Fabric\n# MAGIC Data Pipeline with a recurrence trigger:\n# MAGIC\n# MAGIC 1. Create a **Data Pipeline** in the Fabric workspace\n# MAGIC 2. Add a **Notebook** activity pointing to this notebook\n# MAGIC 3. Set **Parameters**: `source_system`, `batch_size`, `watermark_override`\n# MAGIC 4. Add a **Schedule** trigger: every 5 minutes (or every 15 for z/OS)\n# MAGIC 5. Add failure alerting via Data Activator or Azure Monitor\n# MAGIC\n# MAGIC NOTE: For z/OS sources, the SHIR (Self-hosted Integration Runtime) must\n# MAGIC       be installed in the network segment that can reach the mainframe\n# MAGIC       DRDA port (default 446). The SHIR bridges Fabric to the z/OS DB2\n# MAGIC       Connect gateway without requiring public internet exposure.\n\nprint(\"Schedule via Fabric Data Pipeline for automated near-real-time ingestion.\")\nprint(\"See inline comments for pipeline configuration steps.\")",
    "lang": "pyspark"
  }
];

const CELLS_STREAMING_05_ORACLE_CDC: NotebookCell[] = [
  {
    "id": "streaming-05-oracle-cdc-c0",
    "type": "markdown",
    "source": "# Streaming: Oracle CDC via LogMiner/GoldenGate\n\nCaptures change data from Oracle databases using LogMiner or GoldenGate\nand streams inserts, updates, and deletes into the Bronze Delta Lake layer.\n\n## Architecture\n- **Source:** Oracle DB (ARCHIVELOG mode, supplemental logging enabled)\n- **CDC Method:** LogMiner (built-in) or GoldenGate → Kafka → Eventstreams\n- **Target:** `bronze_cdc_oracle` (Delta Lake, append with operation metadata)\n\n## Prerequisites\n- Oracle JDBC driver JAR on cluster classpath\n- DBA privileges for LogMiner session setup\n- Key Vault secret: `oracle-jdbc-password`"
  },
  {
    "id": "streaming-05-oracle-cdc-c1",
    "type": "markdown",
    "source": "## Configuration"
  },
  {
    "id": "streaming-05-oracle-cdc-c2",
    "type": "code",
    "source": "import os\n\nfrom pyspark.sql import SparkSession\nfrom pyspark.sql.functions import (\n    col,\n    current_timestamp,\n    expr,\n    from_json,\n    lit,\n    regexp_replace,\n    to_timestamp,\n    udf,\n    when,\n)\nfrom pyspark.sql.types import (\n    BooleanType,\n    DecimalType,\n    LongType,\n    StringType,\n    StructField,\n    StructType,\n    TimestampType,\n)\n\n# Oracle JDBC connection parameters — credentials from environment / Key Vault\nORACLE_HOST     = os.getenv(\"ORACLE_HOST\", \"<oracle-host>\")\nORACLE_PORT     = os.getenv(\"ORACLE_PORT\", \"1521\")\nORACLE_SERVICE  = os.getenv(\"ORACLE_SERVICE\", \"CASINOPRD\")\nORACLE_USER     = os.getenv(\"ORACLE_USER\", \"cdc_reader\")\nORACLE_PASSWORD = os.getenv(\"ORACLE_PASSWORD\")          # Key Vault secret\n\nJDBC_URL = f\"jdbc:oracle:thin:@//{ORACLE_HOST}:{ORACLE_PORT}/{ORACLE_SERVICE}\"\n\n# CDC scope\nCDC_TABLES   = [\"CASINO.SLOT_TRANSACTIONS\", \"CASINO.TABLE_GAME_HANDS\"]\nTARGET_TABLE = \"bronze_cdc_oracle\"\nCHECKPOINT   = \"Files/checkpoints/oracle_cdc\"\n\n# LogMiner window (minutes to look back on first run)\nLOGMINER_LOOKBACK_MINUTES = int(os.getenv(\"LOGMINER_LOOKBACK_MINUTES\", \"10\"))\n\nprint(f\"JDBC URL    : {JDBC_URL}\")\nprint(f\"CDC tables  : {CDC_TABLES}\")\nprint(f\"Target table: {TARGET_TABLE}\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-05-oracle-cdc-c3",
    "type": "markdown",
    "source": "## Enable ARCHIVELOG Mode\n\nRun the following SQL as SYSDBA **once** to prepare the Oracle database.\nThese commands must be executed in a SQL*Plus or DBA tool session — they\ncannot be issued over a standard JDBC connection.\n\n```sql\n-- Connect as SYSDBA\nCONNECT / AS SYSDBA;\n\n-- Check current mode\nSELECT log_mode FROM v$database;\n\n-- Enable ARCHIVELOG (requires instance restart)\nSHUTDOWN IMMEDIATE;\nSTARTUP MOUNT;\nALTER DATABASE ARCHIVELOG;\nALTER DATABASE OPEN;\n\n-- Verify\nSELECT log_mode FROM v$database;   -- should return ARCHIVELOG\n```"
  },
  {
    "id": "streaming-05-oracle-cdc-c4",
    "type": "markdown",
    "source": "## Enable Supplemental Logging\n\nSupplemental logging ensures the redo log contains enough column data for CDC.\n\n```sql\n-- Minimum supplemental logging (required)\nALTER DATABASE ADD SUPPLEMENTAL LOG DATA;\n\n-- All-column logging for target tables (recommended for full before/after images)\nALTER TABLE CASINO.SLOT_TRANSACTIONS  ADD SUPPLEMENTAL LOG DATA (ALL) COLUMNS;\nALTER TABLE CASINO.TABLE_GAME_HANDS   ADD SUPPLEMENTAL LOG DATA (ALL) COLUMNS;\n\n-- Grant LogMiner privileges to CDC user\nGRANT EXECUTE ON DBMS_LOGMNR          TO cdc_reader;\nGRANT EXECUTE ON DBMS_LOGMNR_D        TO cdc_reader;\nGRANT SELECT  ON V_$LOGMNR_CONTENTS   TO cdc_reader;\nGRANT SELECT  ON V_$DATABASE          TO cdc_reader;\nGRANT SELECT  ON V_$ARCHIVED_LOG      TO cdc_reader;\nGRANT LOGMINING                        TO cdc_reader;  -- 12c+\n```"
  },
  {
    "id": "streaming-05-oracle-cdc-c5",
    "type": "markdown",
    "source": "## LogMiner Session Setup\n\nOracle LogMiner is invoked via JDBC using PL/SQL anonymous blocks.\nThe following snippet is executed by the `logminer_reader` helper below.\n\n```sql\n-- Add redo log files for the desired time window\nBEGIN\n  DBMS_LOGMNR.ADD_LOGFILE(\n    LOGFILENAME => '/oracle/redo/redo01.log',\n    OPTIONS     => DBMS_LOGMNR.NEW);\nEND;\n\n-- Start LogMiner session with continuous mine + online catalog\nBEGIN\n  DBMS_LOGMNR.START_LOGMNR(\n    STARTTIME => SYSDATE - INTERVAL '10' MINUTE,\n    ENDTIME   => SYSDATE,\n    OPTIONS   => DBMS_LOGMNR.CONTINUOUS_MINE +\n                 DBMS_LOGMNR.DICT_FROM_ONLINE_CATALOG +\n                 DBMS_LOGMNR.NO_ROWID_IN_STMT);\nEND;\n```"
  },
  {
    "id": "streaming-05-oracle-cdc-c6",
    "type": "markdown",
    "source": "## Read Redo Logs via JDBC"
  },
  {
    "id": "streaming-05-oracle-cdc-c7",
    "type": "code",
    "source": "def read_logminer_batch(jdbc_url: str, user: str, password: str,\n                        tables: list, lookback_minutes: int):\n    \"\"\"Query V$LOGMNR_CONTENTS for DML changes on target tables.\"\"\"\n    table_filter = \", \".join(f\"'{t}'\" for t in tables)\n    query = f\"\"\"(\n        SELECT\n            SCN,\n            TIMESTAMP,\n            OPERATION,\n            SEG_OWNER || '.' || TABLE_NAME   AS table_name,\n            SQL_REDO,\n            SQL_UNDO,\n            ROW_ID,\n            XIDUSN, XIDSLT, XIDSQN\n        FROM V$LOGMNR_CONTENTS\n        WHERE OPERATION     IN ('INSERT','UPDATE','DELETE')\n          AND SEG_TYPE_NAME  = 'TABLE'\n          AND SEG_OWNER || '.' || TABLE_NAME IN ({table_filter})\n          AND TIMESTAMP     >= SYSDATE - {lookback_minutes}/1440\n    ) logmnr_q\"\"\"\n\n    return (spark.read.format(\"jdbc\")\n            .option(\"url\",      jdbc_url)\n            .option(\"dbtable\",  query)\n            .option(\"user\",     user)\n            .option(\"password\", password)\n            .option(\"driver\",   \"oracle.jdbc.OracleDriver\")\n            .option(\"fetchsize\", 1000)\n            .load())\n\nraw_cdc_df = read_logminer_batch(JDBC_URL, ORACLE_USER, ORACLE_PASSWORD,\n                                 CDC_TABLES, LOGMINER_LOOKBACK_MINUTES)\nprint(f\"CDC rows fetched: {raw_cdc_df.count()}\")\nraw_cdc_df.printSchema()",
    "lang": "pyspark"
  },
  {
    "id": "streaming-05-oracle-cdc-c8",
    "type": "markdown",
    "source": "## Parse DML Operations"
  },
  {
    "id": "streaming-05-oracle-cdc-c9",
    "type": "code",
    "source": "# Oracle data type mapping applied during cast:\n#   NUMBER(p,s)  → DecimalType(p, s)\n#   VARCHAR2     → StringType\n#   DATE         → TimestampType  (Oracle DATE includes time component)\n#   TIMESTAMP    → TimestampType\n#   CLOB         → StringType     (streamed as text; large CLOBs truncated at 32 KB)\n#   BLOB         → BinaryType     (not recommended for CDC; store reference only)\n\nparsed_cdc_df = (raw_cdc_df\n    .withColumn(\"scn\",           col(\"SCN\").cast(LongType()))\n    .withColumn(\"change_ts\",     col(\"TIMESTAMP\").cast(TimestampType()))\n    .withColumn(\"operation\",     col(\"OPERATION\"))\n    .withColumn(\"table_name\",    col(\"table_name\"))\n    .withColumn(\"sql_redo\",      col(\"SQL_REDO\"))\n    .withColumn(\"sql_undo\",      col(\"SQL_UNDO\"))\n    .withColumn(\"row_id\",        col(\"ROW_ID\"))\n    .withColumn(\"txn_id\",\n        expr(\"CONCAT(XIDUSN, '.', XIDSLT, '.', XIDSQN)\"))\n    .withColumn(\"_ingest_ts\",    current_timestamp())\n    .withColumn(\"_source\",       lit(\"oracle_logminer\"))\n    .select(\"scn\",\"change_ts\",\"operation\",\"table_name\",\n            \"sql_redo\",\"sql_undo\",\"row_id\",\"txn_id\",\n            \"_ingest_ts\",\"_source\"))\n\nparsed_cdc_df.show(5, truncate=80)",
    "lang": "pyspark"
  },
  {
    "id": "streaming-05-oracle-cdc-c10",
    "type": "markdown",
    "source": "## Alternative: GoldenGate → Kafka → Eventstreams\n\nIf LogMiner latency is unacceptable (>30 s) or the Oracle version is older\nthan 11g R2, use GoldenGate to publish changes to Kafka, then connect via\nMicrosoft Fabric Eventstreams (Kafka-compatible endpoint).\n\n```\nOracle DB\n  └─ GoldenGate Extract (trail files)\n      └─ GoldenGate Replicat (Kafka handler)\n          └─ Kafka topic: oracle.casino.cdc\n              └─ Fabric Eventstream (Kafka source connector)\n                  └─ bronze_cdc_oracle (Delta Lake)\n```\n\n**Kafka read snippet for GoldenGate JSON envelope:**\n```python\ngg_schema = StructType([\n    StructField(\"table\",  StringType()),\n    StructField(\"op_type\", StringType()),   # I / U / D\n    StructField(\"op_ts\",  StringType()),\n    StructField(\"before\", StringType()),    # JSON row image\n    StructField(\"after\",  StringType()),\n])\ndf = (spark.readStream.format(\"kafka\")\n      .option(\"kafka.bootstrap.servers\", KAFKA_BROKERS)\n      .option(\"subscribe\", \"oracle.casino.cdc\")\n      .load()\n      .select(from_json(col(\"value\").cast(\"string\"), gg_schema).alias(\"d\"))\n      .select(\"d.*\"))\n```"
  },
  {
    "id": "streaming-05-oracle-cdc-c11",
    "type": "markdown",
    "source": "## Write to Delta Lake"
  },
  {
    "id": "streaming-05-oracle-cdc-c12",
    "type": "code",
    "source": "(parsed_cdc_df.write\n    .format(\"delta\")\n    .mode(\"append\")\n    .option(\"mergeSchema\", \"true\")\n    .saveAsTable(TARGET_TABLE))\n\nprint(f\"Written to {TARGET_TABLE}\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-05-oracle-cdc-c13",
    "type": "markdown",
    "source": "## Monitoring"
  },
  {
    "id": "streaming-05-oracle-cdc-c14",
    "type": "code",
    "source": "# Row counts by operation type\nspark.sql(f\"\"\"\n    SELECT operation, table_name, COUNT(*) AS change_count\n    FROM   {TARGET_TABLE}\n    GROUP  BY operation, table_name\n    ORDER  BY table_name, operation\n\"\"\").show()\n\n# Latest SCN processed (use to set next lookback window)\nspark.sql(f\"\"\"\n    SELECT MAX(scn) AS max_scn, MAX(change_ts) AS latest_change_ts\n    FROM   {TARGET_TABLE}\n\"\"\").show()\n\n# NOTE: In Fabric, schedule this notebook via Data Factory pipeline triggers\n# and pass LOGMINER_LOOKBACK_MINUTES as a parameter to implement micro-batch CDC.\n# For sub-minute latency, deploy the GoldenGate → Eventstreams path instead.",
    "lang": "pyspark"
  }
];

const CELLS_STREAMING_06_KAFKA_CONNECTOR: NotebookCell[] = [
  {
    "id": "streaming-06-kafka-connector-c0",
    "type": "markdown",
    "source": "# Streaming: Apache Kafka Topic Ingestion\n\nReads casino event streams from Apache Kafka (or Fabric Eventstreams\nKafka-compatible endpoint) with SASL/SSL security, deserialization of\nJSON and Avro messages, and real-time windowed aggregations.\n\n## Topics Consumed\n| Topic | Format | Description |\n|---|---|---|\n| `casino.slot-events` | JSON | Spin results, coin-in/out, jackpots |\n| `casino.player-activity` | JSON | Player card events, session lifecycle |\n| `casino.financial-transactions` | Avro | Financial posting events (Schema Registry) |\n\n## Target\n- **Table:** `bronze_kafka_events` (Delta Lake, append)\n- **Checkpoint:** `Files/checkpoints/kafka_events`"
  },
  {
    "id": "streaming-06-kafka-connector-c1",
    "type": "markdown",
    "source": "## Configuration"
  },
  {
    "id": "streaming-06-kafka-connector-c2",
    "type": "code",
    "source": "import os\n\nfrom pyspark.sql import SparkSession\nfrom pyspark.sql.functions import (\n    avg,\n    col,\n    count,\n    current_timestamp,\n    expr,\n    from_avro,\n    from_json,\n    lit,\n    schema_of_json,\n    window,\n)\nfrom pyspark.sql.functions import sum as _sum\nfrom pyspark.sql.types import (\n    BooleanType,\n    DoubleType,\n    IntegerType,\n    LongType,\n    StringType,\n    StructField,\n    StructType,\n    TimestampType,\n)\n\n# Kafka / Eventstreams broker config — credentials from Key Vault / env vars\nKAFKA_BROKERS       = os.getenv(\"KAFKA_BROKERS\",\n                        \"eventhub-ns.servicebus.windows.net:9093\")\nKAFKA_USERNAME      = os.getenv(\"KAFKA_USERNAME\", \"$ConnectionString\")\nKAFKA_PASSWORD      = os.getenv(\"KAFKA_PASSWORD\")          # Key Vault secret\nSCHEMA_REGISTRY_URL = os.getenv(\"SCHEMA_REGISTRY_URL\",\n                        \"https://<schema-registry-host>\")\n\n# Topics\nTOPIC_SLOT_EVENTS     = \"casino.slot-events\"\nTOPIC_PLAYER_ACTIVITY = \"casino.player-activity\"\nTOPIC_FINANCIAL_TXN   = \"casino.financial-transactions\"\nALL_TOPICS            = \",\".join([TOPIC_SLOT_EVENTS,\n                                  TOPIC_PLAYER_ACTIVITY,\n                                  TOPIC_FINANCIAL_TXN])\n\nTARGET_TABLE = \"bronze_kafka_events\"\nCHECKPOINT   = \"Files/checkpoints/kafka_events\"\nWINDOW_DURATION  = \"5 minutes\"\nWATERMARK_DELAY  = \"10 minutes\"\n\nprint(f\"Brokers      : {KAFKA_BROKERS}\")\nprint(f\"Topics       : {ALL_TOPICS}\")\nprint(f\"Target table : {TARGET_TABLE}\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-06-kafka-connector-c3",
    "type": "markdown",
    "source": "## Eventstreams Kafka Endpoint Setup\n\nMicrosoft Fabric Eventstreams exposes a Kafka-compatible endpoint.\nConnect existing Kafka producers without changing client code.\n\n```\nKafka Producer (casino floor systems)\n  └─ Fabric Eventstream (Kafka source)          ← this notebook connects here\n      └─ Custom endpoint (Kafka-compatible)\n          └─ bronze_kafka_events (Delta Lake destination)\n```\n\nSASL JAAS config string (stored in Key Vault, referenced below):\n```\norg.apache.kafka.common.security.plain.PlainLoginModule required\n  username=\"$ConnectionString\"\n  password=\"Endpoint=sb://...;SharedAccessKeyName=...;SharedAccessKey=...\";\n```\n\nNOTE: Fabric Eventstreams also supports a no-code Delta Lake destination.\nUse this notebook when you need custom parsing, enrichment, or aggregations\nbefore writing to the Lakehouse."
  },
  {
    "id": "streaming-06-kafka-connector-c4",
    "type": "markdown",
    "source": "## Read from Kafka Topics"
  },
  {
    "id": "streaming-06-kafka-connector-c5",
    "type": "code",
    "source": "SASL_JAAS = (\n    \"org.apache.kafka.common.security.plain.PlainLoginModule required \"\n    f'username=\"{KAFKA_USERNAME}\" '\n    f'password=\"{KAFKA_PASSWORD}\";'\n)\n\nraw_stream = (spark.readStream\n    .format(\"kafka\")\n    .option(\"kafka.bootstrap.servers\",    KAFKA_BROKERS)\n    .option(\"kafka.security.protocol\",    \"SASL_SSL\")\n    .option(\"kafka.sasl.mechanism\",       \"PLAIN\")\n    .option(\"kafka.sasl.jaas.config\",     SASL_JAAS)\n    .option(\"subscribe\",                  ALL_TOPICS)\n    .option(\"startingOffsets\",            \"latest\")\n    .option(\"maxOffsetsPerTrigger\",       50_000)\n    .option(\"failOnDataLoss\",             \"false\")\n    .load()\n    .withColumn(\"_kafka_topic\",     col(\"topic\"))\n    .withColumn(\"_kafka_partition\", col(\"partition\"))\n    .withColumn(\"_kafka_offset\",    col(\"offset\"))\n    .withColumn(\"_kafka_ts\",        col(\"timestamp\"))\n    .withColumn(\"_ingest_ts\",       current_timestamp())\n    .withColumn(\"raw_value\",        col(\"value\").cast(\"string\")))",
    "lang": "pyspark"
  },
  {
    "id": "streaming-06-kafka-connector-c6",
    "type": "markdown",
    "source": "## Deserialize JSON Messages (Slot Events & Player Activity)"
  },
  {
    "id": "streaming-06-kafka-connector-c7",
    "type": "code",
    "source": "slot_schema = StructType([\n    StructField(\"event_id\",      StringType()),\n    StructField(\"machine_id\",    StringType()),\n    StructField(\"event_type\",    StringType()),\n    StructField(\"event_ts\",      StringType()),\n    StructField(\"denomination\",  DoubleType()),\n    StructField(\"coin_in\",       DoubleType()),\n    StructField(\"coin_out\",      DoubleType()),\n    StructField(\"jackpot_amount\",DoubleType()),\n    StructField(\"player_id\",     StringType()),\n    StructField(\"zone\",          StringType()),\n])\n\nplayer_schema = StructType([\n    StructField(\"session_id\",    StringType()),\n    StructField(\"player_id\",     StringType()),\n    StructField(\"card_number\",   StringType()),\n    StructField(\"event_type\",    StringType()),    # card_in / card_out\n    StructField(\"machine_id\",    StringType()),\n    StructField(\"event_ts\",      StringType()),\n    StructField(\"tier_level\",    StringType()),\n])\n\nslot_stream = (raw_stream\n    .filter(col(\"_kafka_topic\") == TOPIC_SLOT_EVENTS)\n    .withColumn(\"data\", from_json(col(\"raw_value\"), slot_schema))\n    .select(\"_kafka_topic\",\"_kafka_offset\",\"_kafka_ts\",\"_ingest_ts\",\"data.*\"))\n\nplayer_stream = (raw_stream\n    .filter(col(\"_kafka_topic\") == TOPIC_PLAYER_ACTIVITY)\n    .withColumn(\"data\", from_json(col(\"raw_value\"), player_schema))\n    .select(\"_kafka_topic\",\"_kafka_offset\",\"_kafka_ts\",\"_ingest_ts\",\"data.*\"))",
    "lang": "pyspark"
  },
  {
    "id": "streaming-06-kafka-connector-c8",
    "type": "markdown",
    "source": "## Deserialize Avro Messages with Schema Registry\n\nFinancial transactions use Avro with a centralized Schema Registry\nto enforce schema evolution governance."
  },
  {
    "id": "streaming-06-kafka-connector-c9",
    "type": "code",
    "source": "# Fetch Avro schema from registry (cached after first call)\ndef get_avro_schema(subject: str, registry_url: str) -> str:\n    \"\"\"Fetch latest Avro schema JSON string from Confluent Schema Registry.\"\"\"\n    import json\n    import urllib.request\n    url = f\"{registry_url}/subjects/{subject}/versions/latest\"\n    with urllib.request.urlopen(url) as resp:\n        return json.loads(resp.read())[\"schema\"]\n\n# NOTE: In Fabric, store the schema string in a notebook parameter or\n# Key Vault secret to avoid network calls at stream startup.\nFINANCIAL_AVRO_SCHEMA = \"\"\"{\n  \"type\": \"record\", \"name\": \"FinancialTransaction\",\n  \"fields\": [\n    {\"name\": \"txn_id\",      \"type\": \"string\"},\n    {\"name\": \"player_id\",   \"type\": \"string\"},\n    {\"name\": \"machine_id\",  \"type\": \"string\"},\n    {\"name\": \"txn_type\",    \"type\": \"string\"},\n    {\"name\": \"amount\",      \"type\": \"double\"},\n    {\"name\": \"currency\",    \"type\": \"string\"},\n    {\"name\": \"txn_ts\",      \"type\": \"long\",   \"logicalType\": \"timestamp-millis\"},\n    {\"name\": \"cage_id\",     \"type\": \"string\"},\n    {\"name\": \"is_ctr_flag\", \"type\": \"boolean\"}\n  ]\n}\"\"\"\n\nfinancial_stream = (raw_stream\n    .filter(col(\"_kafka_topic\") == TOPIC_FINANCIAL_TXN)\n    # Strip 5-byte Confluent wire-format magic+schema-id prefix before decoding\n    .withColumn(\"avro_payload\", expr(\"substring(value, 6, length(value)-5)\"))\n    .withColumn(\"data\", from_avro(col(\"avro_payload\"), FINANCIAL_AVRO_SCHEMA))\n    .select(\"_kafka_topic\",\"_kafka_offset\",\"_kafka_ts\",\"_ingest_ts\",\"data.*\"))",
    "lang": "pyspark"
  },
  {
    "id": "streaming-06-kafka-connector-c10",
    "type": "markdown",
    "source": "## Multi-Topic Unified Write to Delta Lake"
  },
  {
    "id": "streaming-06-kafka-connector-c11",
    "type": "code",
    "source": "# Flatten all streams to a common envelope schema before writing\ndef normalize_stream(df, topic_label):\n    return (df\n        .withColumn(\"_topic_label\", lit(topic_label))\n        .withColumn(\"raw_payload\",  lit(None).cast(StringType())))\n\n# Write slot events\nslot_query = (slot_stream\n    .withColumn(\"_topic_label\", lit(\"slot_events\"))\n    .writeStream\n    .format(\"delta\")\n    .outputMode(\"append\")\n    .option(\"checkpointLocation\", f\"{CHECKPOINT}/slot\")\n    .option(\"mergeSchema\", \"true\")\n    .toTable(f\"{TARGET_TABLE}_slot\"))\n\n# Write player activity\nplayer_query = (player_stream\n    .withColumn(\"_topic_label\", lit(\"player_activity\"))\n    .writeStream\n    .format(\"delta\")\n    .outputMode(\"append\")\n    .option(\"checkpointLocation\", f\"{CHECKPOINT}/player\")\n    .toTable(f\"{TARGET_TABLE}_player\"))\n\n# Write financial transactions\nfinancial_query = (financial_stream\n    .withColumn(\"_topic_label\", lit(\"financial_txn\"))\n    .writeStream\n    .format(\"delta\")\n    .outputMode(\"append\")\n    .option(\"checkpointLocation\", f\"{CHECKPOINT}/financial\")\n    .toTable(f\"{TARGET_TABLE}_financial\"))\n\nprint(\"All stream queries started.\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-06-kafka-connector-c12",
    "type": "markdown",
    "source": "## Window Aggregations (Slot Revenue — 5-Minute Tumbling Window)"
  },
  {
    "id": "streaming-06-kafka-connector-c13",
    "type": "code",
    "source": "windowed_revenue = (slot_stream\n    .withWatermark(\"event_ts\", WATERMARK_DELAY)\n    .groupBy(\n        window(col(\"event_ts\"), WINDOW_DURATION),\n        col(\"zone\"),\n        col(\"denomination\"))\n    .agg(\n        count(\"*\").alias(\"spin_count\"),\n        _sum(\"coin_in\").alias(\"total_coin_in\"),\n        _sum(\"coin_out\").alias(\"total_coin_out\"),\n        _sum(\"jackpot_amount\").alias(\"total_jackpot\")))\n\nwindowed_query = (windowed_revenue\n    .writeStream\n    .format(\"delta\")\n    .outputMode(\"append\")\n    .option(\"checkpointLocation\", f\"{CHECKPOINT}/windowed\")\n    .toTable(\"silver_kafka_slot_revenue_5min\"))",
    "lang": "pyspark"
  },
  {
    "id": "streaming-06-kafka-connector-c14",
    "type": "markdown",
    "source": "## Monitoring: Consumer Lag and Throughput"
  },
  {
    "id": "streaming-06-kafka-connector-c15",
    "type": "code",
    "source": "# Check stream progress for all active queries\nfor q in spark.streams.active:\n    prog = q.lastProgress\n    if prog:\n        print(f\"Query     : {q.name or q.id}\")\n        print(f\"  Rows/sec (input) : {prog.get('inputRowsPerSecond', 'N/A'):.1f}\")\n        print(f\"  Rows/sec (proc)  : {prog.get('processedRowsPerSecond', 'N/A'):.1f}\")\n        offsets = prog.get(\"sources\", [{}])[0].get(\"endOffset\", {})\n        print(f\"  End offsets      : {offsets}\")\n        print()\n\n# NOTE: Fabric Eventstreams provides a built-in Monitoring hub that shows\n# consumer-group lag per partition without requiring custom KQL queries.\n# For Confluent Kafka, use kafka-consumer-groups.sh or Confluent Control Center.",
    "lang": "pyspark"
  }
];

const CELLS_STREAMING_07_IOT_HUB_INGESTION: NotebookCell[] = [
  {
    "id": "streaming-07-iot-hub-ingestion-c0",
    "type": "markdown",
    "source": "# Streaming: Azure IoT Hub Device-to-Cloud Messages\n\nReads device telemetry from the Azure IoT Hub built-in Event Hub-compatible\nendpoint, routes messages by device type, enriches with device metadata,\nand writes to a partitioned Bronze Delta Lake table.\n\n## Device Types\n| Device Type | Volume | Key Signals |\n|---|---|---|\n| `slot_machine` | ~500 devices, 2 msg/min each | coin-in, coin-out, door, tilt |\n| `table_sensor` | ~80 sensors, 1 msg/min each | chip tray weight, card count |\n| `hvac_sensor` | ~120 sensors, 1 msg/15 min | temp, humidity, airflow |\n| `door_sensor` | ~300 sensors, event-driven | open/close, badge swipe |\n\n## Target\n- **Table:** `bronze_iot_telemetry` partitioned by `device_type`\n- **Checkpoint:** `Files/checkpoints/iot_hub`"
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c1",
    "type": "markdown",
    "source": "## Configuration"
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c2",
    "type": "code",
    "source": "import os\n\nfrom pyspark.sql import SparkSession\nfrom pyspark.sql.functions import (\n    broadcast,\n    col,\n    current_timestamp,\n    expr,\n    from_json,\n    get_json_object,\n    lit,\n    to_timestamp,\n    when,\n)\nfrom pyspark.sql.types import (\n    BooleanType,\n    DoubleType,\n    IntegerType,\n    LongType,\n    MapType,\n    StringType,\n    StructField,\n    StructType,\n    TimestampType,\n)\n\n# IoT Hub / Event Hub-compatible endpoint — credentials from Key Vault\nIOT_HUB_NAME        = os.getenv(\"IOT_HUB_NAME\", \"casino-iothub\")\nIOT_HUB_NAMESPACE   = f\"{IOT_HUB_NAME}.servicebus.windows.net\"\nIOT_HUB_POLICY_KEY  = os.getenv(\"IOT_HUB_POLICY_KEY\")    # Key Vault secret\nIOT_HUB_CONSUMER_GRP = os.getenv(\"IOT_HUB_CONSUMER_GROUP\", \"fabric-spark-cg\")\n\n# Built-in Event Hub-compatible endpoint details\nEVENTHUB_NAME        = \"messages/events\"                   # built-in endpoint name\nEVENTHUB_CONN_STRING = (\n    f\"Endpoint=sb://{IOT_HUB_NAMESPACE}/;\"\n    f\"SharedAccessKeyName=service;SharedAccessKey={IOT_HUB_POLICY_KEY};\"\n    f\"EntityPath={EVENTHUB_NAME}\"\n)\n\nTARGET_TABLE = \"bronze_iot_telemetry\"\nCHECKPOINT   = \"Files/checkpoints/iot_hub\"\nDEVICE_META_PATH = \"Files/reference/iot_device_metadata.parquet\"\n\nprint(f\"IoT Hub    : {IOT_HUB_NAME}\")\nprint(f\"Consumer Grp: {IOT_HUB_CONSUMER_GRP}\")\nprint(f\"Target table: {TARGET_TABLE}\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c3",
    "type": "markdown",
    "source": "## Read from IoT Hub Built-In Event Hub Endpoint\n\nIoT Hub exposes a built-in Event Hub-compatible endpoint for device messages.\nNo separate Azure Event Hubs namespace is required — the connection string\nuses the IoT Hub's hostname and a shared access policy key.\n\nNOTE: Create a dedicated consumer group (`fabric-spark-cg`) in the Azure\nPortal under IoT Hub → Built-in endpoints → Consumer groups. Never use\n`$Default` in production to avoid competing with other readers."
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c4",
    "type": "code",
    "source": "# Event Hub connection config for Spark structured streaming\nEH_CONF = {\n    \"eventhubs.connectionString\":\n        sc._jvm.org.apache.spark.eventhubs.EventHubsUtils\n              .encrypt(EVENTHUB_CONN_STRING),\n    \"eventhubs.consumerGroup\":   IOT_HUB_CONSUMER_GRP,\n    \"eventhubs.startingPosition\": '{\"offset\": \"-1\", \"seqNo\": -1, \"enqueuedTime\": null, \"isInclusive\": true}',\n    \"maxEventsPerTrigger\":        10_000,\n}\n\nraw_iot_stream = (spark.readStream\n    .format(\"eventhubs\")\n    .options(**EH_CONF)\n    .load()\n    .withColumn(\"raw_body\",     col(\"body\").cast(\"string\"))\n    .withColumn(\"enqueued_ts\",  col(\"enqueuedTime\"))\n    .withColumn(\"_ingest_ts\",   current_timestamp())\n    .withColumn(\"iothub_device_id\",\n        col(\"systemProperties\")[\"iothub-connection-device-id\"].cast(\"string\"))\n    .withColumn(\"iothub_module_id\",\n        col(\"systemProperties\")[\"iothub-connection-module-id\"].cast(\"string\")))",
    "lang": "pyspark"
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c5",
    "type": "markdown",
    "source": "## Parse Device Telemetry JSON"
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c6",
    "type": "code",
    "source": "# Base telemetry schema — all device types share these root fields\nbase_schema = StructType([\n    StructField(\"device_id\",      StringType()),\n    StructField(\"device_type\",    StringType()),    # slot_machine | table_sensor | hvac_sensor | door_sensor\n    StructField(\"event_type\",     StringType()),\n    StructField(\"event_ts\",       StringType()),\n    StructField(\"firmware_ver\",   StringType()),\n    StructField(\"location_id\",    StringType()),\n    StructField(\"zone\",           StringType()),\n    StructField(\"payload\",        MapType(StringType(), StringType())),  # device-type-specific fields\n])\n\nparsed_stream = (raw_iot_stream\n    .withColumn(\"telemetry\", from_json(col(\"raw_body\"), base_schema))\n    .select(\n        col(\"iothub_device_id\"),\n        col(\"enqueued_ts\"),\n        col(\"_ingest_ts\"),\n        col(\"telemetry.device_id\").alias(\"device_id\"),\n        col(\"telemetry.device_type\").alias(\"device_type\"),\n        col(\"telemetry.event_type\").alias(\"event_type\"),\n        to_timestamp(col(\"telemetry.event_ts\")).alias(\"event_ts\"),\n        col(\"telemetry.firmware_ver\").alias(\"firmware_ver\"),\n        col(\"telemetry.location_id\").alias(\"location_id\"),\n        col(\"telemetry.zone\").alias(\"zone\"),\n        col(\"telemetry.payload\").alias(\"payload\"),\n    ))",
    "lang": "pyspark"
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c7",
    "type": "markdown",
    "source": "## Route by Device Type"
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c8",
    "type": "code",
    "source": "# Slot machine telemetry — extract SAS meter fields from payload map\nslot_stream = (parsed_stream\n    .filter(col(\"device_type\") == \"slot_machine\")\n    .withColumn(\"coin_in_meter\",\n        col(\"payload\")[\"coin_in_meter\"].cast(DoubleType()))\n    .withColumn(\"coin_out_meter\",\n        col(\"payload\")[\"coin_out_meter\"].cast(DoubleType()))\n    .withColumn(\"games_played\",\n        col(\"payload\")[\"games_played\"].cast(LongType()))\n    .withColumn(\"door_open\",\n        col(\"payload\")[\"door_open\"].cast(BooleanType()))\n    .withColumn(\"tilt_code\",\n        col(\"payload\")[\"tilt_code\"]))\n\n# HVAC sensor telemetry\nhvac_stream = (parsed_stream\n    .filter(col(\"device_type\") == \"hvac_sensor\")\n    .withColumn(\"temperature_c\",\n        col(\"payload\")[\"temperature_c\"].cast(DoubleType()))\n    .withColumn(\"humidity_pct\",\n        col(\"payload\")[\"humidity_pct\"].cast(DoubleType()))\n    .withColumn(\"airflow_cfm\",\n        col(\"payload\")[\"airflow_cfm\"].cast(DoubleType())))\n\n# Door sensor telemetry\ndoor_stream = (parsed_stream\n    .filter(col(\"device_type\") == \"door_sensor\")\n    .withColumn(\"door_state\",\n        col(\"payload\")[\"door_state\"])\n    .withColumn(\"badge_id\",\n        col(\"payload\")[\"badge_id\"])\n    .withColumn(\"access_granted\",\n        col(\"payload\")[\"access_granted\"].cast(BooleanType())))\n\n# Table sensor telemetry\ntable_stream = (parsed_stream\n    .filter(col(\"device_type\") == \"table_sensor\")\n    .withColumn(\"chip_tray_value\",\n        col(\"payload\")[\"chip_tray_value\"].cast(DoubleType()))\n    .withColumn(\"card_count\",\n        col(\"payload\")[\"card_count\"].cast(IntegerType()))\n    .withColumn(\"shuffle_count\",\n        col(\"payload\")[\"shuffle_count\"].cast(IntegerType())))",
    "lang": "pyspark"
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c9",
    "type": "markdown",
    "source": "## Enrich with Device Metadata"
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c10",
    "type": "code",
    "source": "# Static device registry (refreshed daily by a Data Factory pipeline)\n# NOTE: In Fabric, store this as a Delta table in lh_silver and read via\n# spark.read.table() so updates propagate automatically.\ndevice_meta_df = (spark.read\n    .format(\"parquet\")\n    .load(DEVICE_META_PATH))\n\n# Broadcast join — metadata is small (~50 K rows)\nslot_enriched = (slot_stream\n    .join(broadcast(device_meta_df), on=\"device_id\", how=\"left\")\n    .withColumn(\"_source\", lit(\"iot_hub\")))",
    "lang": "pyspark"
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c11",
    "type": "markdown",
    "source": "## Write to Partitioned Delta Lake Tables"
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c12",
    "type": "code",
    "source": "# Message routing rules:\n#   slot_machine  → bronze_iot_telemetry / device_type=slot_machine\n#   hvac_sensor   → bronze_iot_telemetry / device_type=hvac_sensor\n#   door_sensor   → bronze_iot_telemetry / device_type=door_sensor\n#   table_sensor  → bronze_iot_telemetry / device_type=table_sensor\n\ndef write_routed_stream(df, device_type_label, checkpoint_suffix):\n    return (df\n        .withColumn(\"device_type\", lit(device_type_label))\n        .writeStream\n        .format(\"delta\")\n        .outputMode(\"append\")\n        .partitionBy(\"device_type\")\n        .option(\"checkpointLocation\", f\"{CHECKPOINT}/{checkpoint_suffix}\")\n        .option(\"mergeSchema\", \"true\")\n        .toTable(TARGET_TABLE))\n\nslot_q   = write_routed_stream(slot_enriched,  \"slot_machine\",  \"slot\")\nhvac_q   = write_routed_stream(hvac_stream,    \"hvac_sensor\",   \"hvac\")\ndoor_q   = write_routed_stream(door_stream,    \"door_sensor\",   \"door\")\ntable_q  = write_routed_stream(table_stream,   \"table_sensor\",  \"table\")\n\nprint(f\"4 routed stream queries writing to {TARGET_TABLE}\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c13",
    "type": "markdown",
    "source": "## Device Health Monitoring Queries"
  },
  {
    "id": "streaming-07-iot-hub-ingestion-c14",
    "type": "code",
    "source": "# Last-seen timestamp per device (run interactively or via scheduled notebook)\nspark.sql(f\"\"\"\n    SELECT device_type,\n           device_id,\n           MAX(event_ts)             AS last_seen_ts,\n           COUNT(*)                  AS msg_count_today,\n           DATEDIFF(NOW(), MAX(event_ts)) AS minutes_since_last_msg\n    FROM   {TARGET_TABLE}\n    WHERE  event_ts >= CURRENT_DATE\n    GROUP  BY device_type, device_id\n    HAVING minutes_since_last_msg > 30       -- flag silent devices\n    ORDER  BY minutes_since_last_msg DESC\n\"\"\").show(20)\n\n# Tilt / fault summary for slot machines\nspark.sql(f\"\"\"\n    SELECT zone,\n           tilt_code,\n           COUNT(*)  AS tilt_count,\n           COUNT(DISTINCT device_id) AS affected_machines\n    FROM   {TARGET_TABLE}\n    WHERE  device_type = 'slot_machine'\n      AND  tilt_code IS NOT NULL\n      AND  event_ts  >= CURRENT_DATE\n    GROUP  BY zone, tilt_code\n    ORDER  BY tilt_count DESC\n\"\"\").show()\n\n# NOTE: Connect an Eventhouse KQL database to bronze_iot_telemetry via a\n# Fabric shortcut to enable sub-second anomaly detection without data copy.",
    "lang": "pyspark"
  }
];

const CELLS_STREAMING_08_SLOT_MACHINE_IOT_SIMULATOR: NotebookCell[] = [
  {
    "id": "streaming-08-slot-machine-iot-simulator-c0",
    "type": "markdown",
    "source": "# Streaming: Custom Slot Machine SAS Protocol IoT Simulator\n\n**This notebook is a PRODUCER, not a consumer.**\nIt generates realistic slot machine telemetry conforming to the\nSAS (Slot Accounting System) protocol and sends it to an Azure\nEvent Hub or IoT Hub at configurable throughput rates.\n\nUse this simulator to:\n- Load-test downstream Eventstream and Lakehouse pipelines\n- Generate realistic data for POC demonstrations\n- Validate Bronze ingestion notebooks (07) without physical hardware\n\n## SAS Event Types Generated\n| Event Type | Description |\n|---|---|\n| `spin_result` | Reel outcome, coin-in, coin-out, win amount |\n| `coin_in` | Bill/coin acceptor — denomination inserted |\n| `coin_out` | Hopper/ticket dispenser — credit paid out |\n| `jackpot` | Progressive or standalone jackpot hit |\n| `door_open` | Cabinet door opened (maintenance/fill) |\n| `tilt` | Machine fault — includes tilt code |\n| `power_event` | Machine power-up or power-down |\n| `meter_read` | Periodic meter snapshot (all accumulators) |\n\n## Target\n- **Destination:** Azure Event Hub (or IoT Hub device endpoint)\n- **Rate:** 50–500 events/second (configurable)"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c1",
    "type": "markdown",
    "source": "## Configuration"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c2",
    "type": "code",
    "source": "import json\nimport os\nimport random\nimport threading\nimport time\nimport uuid\nfrom dataclasses import asdict, dataclass, field\nfrom datetime import datetime, timedelta\nfrom typing import Dict, List, Optional\n\n# Event Hub / IoT Hub target — credentials from Key Vault / env vars\nEVENTHUB_CONN_STRING = os.getenv(\"EVENTHUB_CONN_STRING\")   # Key Vault secret\nEVENTHUB_NAME        = os.getenv(\"EVENTHUB_NAME\", \"casino-slot-events\")\n\n# Throughput controls\nTARGET_EVENTS_PER_SEC = int(os.getenv(\"TARGET_EVENTS_PER_SEC\", \"100\"))\nBATCH_SIZE            = int(os.getenv(\"BATCH_SIZE\", \"50\"))       # events per send call\nSIMULATION_MINUTES    = int(os.getenv(\"SIMULATION_MINUTES\", \"5\"))\nNUM_MACHINES          = int(os.getenv(\"NUM_MACHINES\", \"200\"))    # virtual slot machines\n\n# SAS protocol weights — realistic event distribution\nEVENT_WEIGHTS = {\n    \"spin_result\": 70,\n    \"coin_in\":     10,\n    \"coin_out\":     8,\n    \"meter_read\":   5,\n    \"door_open\":    3,\n    \"tilt\":         2,\n    \"jackpot\":      1,\n    \"power_event\":  1,\n}\n\nprint(f\"Target EH    : {EVENTHUB_NAME}\")\nprint(f\"Rate (evt/s) : {TARGET_EVENTS_PER_SEC}\")\nprint(f\"Batch size   : {BATCH_SIZE}\")\nprint(f\"Duration     : {SIMULATION_MINUTES} minutes\")\nprint(f\"Machines     : {NUM_MACHINES}\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c3",
    "type": "markdown",
    "source": "## SAS Protocol Field Definitions\n\nAll meter fields accumulate from machine power-up (never reset by operator).\nDifferences between consecutive meter reads represent activity in the interval.\n\n| Field | Type | Description |\n|---|---|---|\n| `machine_number` | str | Physical asset tag (1–NUM_MACHINES) |\n| `denomination` | float | Bet unit: 0.01, 0.02, 0.05, 0.25, 1.00, 5.00 |\n| `game_id` | str | Game theme identifier (e.g. WOLF_RUN_3) |\n| `coin_in_meter` | int | Cumulative credits wagered (in units of $0.01) |\n| `coin_out_meter` | int | Cumulative credits paid out |\n| `games_played_meter` | int | Cumulative spins |\n| `jackpot_meter` | int | Cumulative jackpot amount paid |\n| `bill_in_meter` | int | Cumulative bills accepted (dollar value × 100) |\n| `handpay_amount` | int | Amount requiring attendant handpay ($0.01 units) |\n| `progressive_amount` | int | Current progressive jackpot level ($0.01 units) |"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c4",
    "type": "markdown",
    "source": "## Machine State Model"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c5",
    "type": "code",
    "source": "DENOMINATIONS   = [0.01, 0.02, 0.05, 0.25, 1.00, 5.00]\nGAME_IDS        = [\"WOLF_RUN_3\",\"BUFFALO_GOLD\",\"LIGHTNING_LINK\",\n                   \"DRAGON_LINK\",\"DANCING_DRUMS\",\"GOLDEN_CENTURY\",\n                   \"5_DRAGONS\",\"GOLDEN_GODDESS\",\"MYSTICAL_MERMAID\"]\nTILT_CODES      = [\"51\",\"52\",\"53\",\"55\",\"61\",\"62\",\"70\",\"71\",\"FF\"]  # SAS fault codes\nLOCATIONS       = [f\"ZONE_{z}\" for z in [\"A\",\"B\",\"C\",\"D\",\"E\"]]\nZONES           = LOCATIONS\n\n@dataclass\nclass SlotMachineState:\n    \"\"\"Mutable state for a single virtual slot machine.\"\"\"\n    machine_number:      str\n    denomination:        float\n    game_id:             str\n    location_id:         str\n    zone:                str\n    firmware_ver:        str = \"SAS_6.03\"\n    coin_in_meter:       int = 0\n    coin_out_meter:      int = 0\n    games_played_meter:  int = 0\n    jackpot_meter:       int = 0\n    bill_in_meter:       int = 0\n    progressive_amount:  int = field(default_factory=lambda: random.randint(100_000, 5_000_000))\n    is_door_open:        bool = False\n    is_powered:          bool = True\n\ndef init_machines(n: int) -> list[SlotMachineState]:\n    machines = []\n    for i in range(1, n + 1):\n        denom = random.choice(DENOMINATIONS)\n        zone  = random.choice(ZONES)\n        machines.append(SlotMachineState(\n            machine_number=f\"SLT{i:04d}\",\n            denomination=denom,\n            game_id=random.choice(GAME_IDS),\n            location_id=f\"LOC_{i:04d}\",\n            zone=zone,\n            coin_in_meter=random.randint(0, 10_000_000),\n            coin_out_meter=random.randint(0, 9_000_000),\n            games_played_meter=random.randint(0, 500_000),\n        ))\n    return machines\n\nmachines = init_machines(NUM_MACHINES)\nprint(f\"Initialized {len(machines)} virtual slot machines.\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c6",
    "type": "markdown",
    "source": "## Event Generators"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c7",
    "type": "code",
    "source": "def base_envelope(m: SlotMachineState, event_type: str) -> dict:\n    return {\n        \"event_id\":     str(uuid.uuid4()),\n        \"device_id\":    m.machine_number,\n        \"device_type\":  \"slot_machine\",\n        \"event_type\":   event_type,\n        \"event_ts\":     datetime.utcnow().isoformat() + \"Z\",\n        \"machine_number\": m.machine_number,\n        \"denomination\": m.denomination,\n        \"game_id\":      m.game_id,\n        \"location_id\":  m.location_id,\n        \"zone\":         m.zone,\n        \"firmware_ver\": m.firmware_ver,\n    }\n\ndef generate_spin_result(m: SlotMachineState) -> dict:\n    bet     = max(1, int(random.gauss(3, 1)))          # lines × bet multiplier\n    coin_in = int(m.denomination * 100 * bet)\n    win_mul = random.choices([0, 1, 2, 5, 10, 50, 100],\n                              weights=[55, 20, 12, 7, 4, 1.5, 0.5])[0]\n    coin_out = coin_in * win_mul\n    m.coin_in_meter     += coin_in\n    m.coin_out_meter    += coin_out\n    m.games_played_meter += 1\n    ev = base_envelope(m, \"spin_result\")\n    ev.update({\"bet_credits\": bet, \"win_credits\": win_mul * bet,\n                \"coin_in\": coin_in, \"coin_out\": coin_out,\n                \"coin_in_meter\": m.coin_in_meter,\n                \"coin_out_meter\": m.coin_out_meter,\n                \"games_played_meter\": m.games_played_meter})\n    return ev\n\ndef generate_jackpot(m: SlotMachineState) -> dict:\n    amount = random.choice([\n        random.randint(1200, 5000),    # minor\n        random.randint(5001, 25000),   # major\n        m.progressive_amount,          # progressive\n    ])\n    requires_handpay = amount >= 120_000   # $1,200 W-2G threshold × 100\n    m.jackpot_meter     += amount\n    m.coin_out_meter    += amount\n    m.progressive_amount = random.randint(100_000, 5_000_000)   # reset\n    ev = base_envelope(m, \"jackpot\")\n    ev.update({\"jackpot_amount\": amount,\n                \"requires_handpay\": requires_handpay,\n                \"handpay_amount\": amount if requires_handpay else 0,\n                \"jackpot_meter\": m.jackpot_meter,\n                \"progressive_amount\": m.progressive_amount})\n    return ev\n\ndef generate_coin_in(m: SlotMachineState) -> dict:\n    bills = [100, 200, 500, 1000, 2000, 5000, 10000]  # $1–$100 in cents\n    bill_val = random.choice(bills)\n    m.bill_in_meter += bill_val\n    ev = base_envelope(m, \"coin_in\")\n    ev.update({\"bill_denomination\": bill_val,\n                \"bill_in_meter\": m.bill_in_meter})\n    return ev\n\ndef generate_coin_out(m: SlotMachineState) -> dict:\n    tito_amount = random.randint(100, 50000)  # TITO ticket value in cents\n    m.coin_out_meter += tito_amount\n    ev = base_envelope(m, \"coin_out\")\n    ev.update({\"tito_amount\": tito_amount, \"coin_out_meter\": m.coin_out_meter})\n    return ev\n\ndef generate_door_event(m: SlotMachineState) -> dict:\n    m.is_door_open = not m.is_door_open\n    ev = base_envelope(m, \"door_open\")\n    ev.update({\"door_state\": \"open\" if m.is_door_open else \"closed\",\n                \"door_type\": random.choice([\"main_door\",\"bill_validator_door\",\"drop_door\"]),\n                \"badge_id\": f\"EMP{random.randint(1000,9999)}\"})\n    return ev\n\ndef generate_tilt(m: SlotMachineState) -> dict:\n    ev = base_envelope(m, \"tilt\")\n    ev.update({\"tilt_code\": random.choice(TILT_CODES),\n                \"tilt_description\": \"SAS fault detected\",\n                \"auto_recoverable\": random.random() > 0.3})\n    return ev\n\ndef generate_power_event(m: SlotMachineState) -> dict:\n    ev = base_envelope(m, \"power_event\")\n    ev.update({\"power_state\": \"up\" if m.is_powered else \"down\",\n                \"reset_type\": random.choice([\"normal\",\"watchdog\",\"power_fail\"])})\n    return ev\n\ndef generate_meter_read(m: SlotMachineState) -> dict:\n    ev = base_envelope(m, \"meter_read\")\n    ev.update({\n        \"coin_in_meter\":       m.coin_in_meter,\n        \"coin_out_meter\":      m.coin_out_meter,\n        \"games_played_meter\":  m.games_played_meter,\n        \"jackpot_meter\":       m.jackpot_meter,\n        \"bill_in_meter\":       m.bill_in_meter,\n        \"progressive_amount\":  m.progressive_amount,\n        \"meter_read_reason\":   random.choice([\"scheduled\",\"door_close\",\"power_up\"]),\n    })\n    return ev\n\nEVENT_GENERATORS = {\n    \"spin_result\":  generate_spin_result,\n    \"coin_in\":      generate_coin_in,\n    \"coin_out\":     generate_coin_out,\n    \"jackpot\":      generate_jackpot,\n    \"door_open\":    generate_door_event,\n    \"tilt\":         generate_tilt,\n    \"power_event\":  generate_power_event,\n    \"meter_read\":   generate_meter_read,\n}\n\nEVENT_TYPES = list(EVENT_WEIGHTS.keys())\nEVENT_WVALS = [EVENT_WEIGHTS[e] for e in EVENT_TYPES]\n\ndef next_event(machine: SlotMachineState) -> dict:\n    event_type = random.choices(EVENT_TYPES, weights=EVENT_WVALS)[0]\n    return EVENT_GENERATORS[event_type](machine)",
    "lang": "pyspark"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c8",
    "type": "markdown",
    "source": "## Send to Event Hub — Batch Optimization"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c9",
    "type": "code",
    "source": "# NOTE: Install azure-eventhub on the Fabric cluster:\n#   %pip install azure-eventhub\n# Or add to the environment via Workspace Settings → Libraries.\n\nfrom azure.eventhub import EventData, EventHubProducerClient\nfrom azure.eventhub.exceptions import EventHubError\n\n\ndef create_producer() -> EventHubProducerClient:\n    return EventHubProducerClient.from_connection_string(\n        conn_str=EVENTHUB_CONN_STRING,\n        eventhub_name=EVENTHUB_NAME,\n    )\n\ndef send_batch(producer: EventHubProducerClient,\n               events: list[dict]) -> int:\n    \"\"\"Pack events into an EventDataBatch (respects 1 MB limit) and send.\"\"\"\n    event_data_batch = producer.create_batch()\n    overflow = []\n    for ev in events:\n        try:\n            event_data_batch.add(EventData(json.dumps(ev, default=str)))\n        except ValueError:          # batch full — start a new one\n            producer.send_batch(event_data_batch)\n            event_data_batch = producer.create_batch()\n            event_data_batch.add(EventData(json.dumps(ev, default=str)))\n    if len(event_data_batch) > 0:\n        producer.send_batch(event_data_batch)\n    return len(events)",
    "lang": "pyspark"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c10",
    "type": "markdown",
    "source": "## Configurable Throughput with Rate Limiting and Back-Pressure"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c11",
    "type": "code",
    "source": "# Stats accumulator (thread-safe via GIL for simple int ops)\nstats = {\"sent\": 0, \"errors\": 0, \"batches\": 0}\n_stop_event = threading.Event()\n\ndef run_simulator():\n    \"\"\"Main simulation loop — runs until SIMULATION_MINUTES elapses or stop().\"\"\"\n    producer = create_producer()\n    end_time = time.monotonic() + SIMULATION_MINUTES * 60\n    interval = BATCH_SIZE / TARGET_EVENTS_PER_SEC   # seconds between batch sends\n\n    print(f\"Simulation started. Target: {TARGET_EVENTS_PER_SEC} evt/s \"\n          f\"| Batch: {BATCH_SIZE} | Duration: {SIMULATION_MINUTES} min\")\n\n    try:\n        while not _stop_event.is_set() and time.monotonic() < end_time:\n            t0 = time.monotonic()\n\n            # Generate one batch\n            batch_machines = random.choices(machines, k=BATCH_SIZE)\n            batch_events   = [next_event(m) for m in batch_machines]\n\n            try:\n                sent = send_batch(producer, batch_events)\n                stats[\"sent\"]    += sent\n                stats[\"batches\"] += 1\n            except EventHubError as exc:\n                stats[\"errors\"] += 1\n                # Back-pressure: wait 2 s on transient errors, then retry\n                print(f\"[WARN] EventHub error ({exc}); backing off 2 s\")\n                time.sleep(2)\n                continue\n\n            # Rate limiting: sleep for the remainder of the interval\n            elapsed = time.monotonic() - t0\n            sleep_s = max(0.0, interval - elapsed)\n            if sleep_s > 0:\n                time.sleep(sleep_s)\n\n    finally:\n        producer.close()\n        print(f\"\\nSimulation complete. \"\n              f\"Sent: {stats['sent']:,} | \"\n              f\"Batches: {stats['batches']:,} | \"\n              f\"Errors: {stats['errors']}\")\n\ndef stop_simulator():\n    \"\"\"Graceful shutdown — call from a separate cell or interrupt.\"\"\"\n    _stop_event.set()\n    print(\"Stop signal sent. Simulator will finish current batch and exit.\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c12",
    "type": "markdown",
    "source": "## Start Simulation"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c13",
    "type": "code",
    "source": "# Run in a background thread so the notebook cell returns immediately\n# and allows the monitoring cell below to execute concurrently.\nsim_thread = threading.Thread(target=run_simulator, daemon=True)\nsim_thread.start()\nprint(\"Simulator running in background thread. \"\n      \"Run the next cell to monitor, or call stop_simulator() to halt.\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c14",
    "type": "markdown",
    "source": "## Statistics and Monitoring"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c15",
    "type": "code",
    "source": "import time as _time\n\n# Poll stats every 10 seconds for 60 seconds\nfor i in range(6):\n    _time.sleep(10)\n    elapsed_s = (i + 1) * 10\n    rate = stats[\"sent\"] / elapsed_s if elapsed_s > 0 else 0\n    print(f\"[{elapsed_s:3d}s] Sent: {stats['sent']:7,} | \"\n          f\"Rate: {rate:6.1f} evt/s | \"\n          f\"Batches: {stats['batches']:5,} | \"\n          f\"Errors: {stats['errors']}\")",
    "lang": "pyspark"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c16",
    "type": "markdown",
    "source": "## Graceful Shutdown"
  },
  {
    "id": "streaming-08-slot-machine-iot-simulator-c17",
    "type": "code",
    "source": "# Uncomment to stop the simulator before SIMULATION_MINUTES elapses:\n# stop_simulator()\n# sim_thread.join(timeout=10)\n# print(\"Simulator stopped.\")\n\n# NOTE: If running in a Fabric scheduled pipeline, set SIMULATION_MINUTES\n# to match the pipeline trigger interval (e.g. 60 for hourly load tests).\n# The simulator will exit cleanly when the time window expires.",
    "lang": "pyspark"
  }
];

